import { APP_NAME } from "@/lib/constants";
import Link from "next/link";
import Image from "next/image";

export default function AuthLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <div className="min-h-screen flex flex-col bg-surface-lowest">
      {/* Top Banner - Hero Image with Overlay */}
      <div className="relative w-full h-[40vh] min-h-[300px] flex items-center justify-center overflow-hidden">
        {/* Abstract dark green botanical background placeholder */}
        <div className="absolute inset-0 bg-[#0a1e12]">
          <div className="absolute inset-0 opacity-40 bg-[url('https://images.unsplash.com/photo-1518531933037-91b2f5f229cc?q=80&w=2574&auto=format&fit=crop')] bg-cover bg-center" />
          <div className="absolute inset-0 bg-gradient-to-t from-[#0a1e12] via-transparent to-transparent opacity-80" />
        </div>

        {/* Floating Glass Box */}
        <div className="relative z-10 px-12 py-8 bg-surface-lowest/10 backdrop-blur-md border border-surface-lowest/20 rounded-2xl flex flex-col items-center">
          <Link href="/">
            <h1 className="font-serif text-4xl sm:text-5xl font-bold text-white tracking-tight mb-2 text-center">
              {APP_NAME}
            </h1>
          </Link>
          <p className="text-white/80 text-xs sm:text-sm tracking-[0.2em] uppercase font-medium">
            Curating Your Sanctuary
          </p>
        </div>
      </div>

      {/* Main Content - Form Area */}
      <div className="flex-1 flex flex-col items-center px-4 py-8">
        <div className="w-full max-w-md">
          {children}
        </div>
      </div>

      {/* Footer Area */}
      <footer className="bg-primary/5 py-12 px-6 sm:px-12 mt-auto">
        <div className="max-w-4xl mx-auto flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
          <div className="space-y-2">
            <h2 className="font-serif text-xl font-bold text-primary-fixed-variant">
              {APP_NAME}
            </h2>
            <p className="text-sm text-primary/70">
              © {new Date().getFullYear()} {APP_NAME} Botanical Archivist. All rights reserved.
            </p>
          </div>
          <div className="flex flex-wrap gap-6 text-sm text-primary/70">
            <Link href="/privacy" className="hover:text-primary transition-colors">Privacy Policy</Link>
            <Link href="/terms" className="hover:text-primary transition-colors">Terms of Service</Link>
            <Link href="/contact" className="hover:text-primary transition-colors">Contact Us</Link>
          </div>
        </div>
      </footer>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { MapPin, Plus, Edit2, Trash2, Home, Building, Loader2, Check } from "lucide-react";
import { toast } from "sonner";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Breadcrumbs } from "@/components/shared/breadcrumbs";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";

interface SavedAddress {
  id: string;
  label: string;
  full_name: string;
  phone: string;
  address_line1: string;
  address_line2: string | null;
  city: string;
  state: string;
  pin_code: string;
  landmark: string | null;
  is_default: boolean;
}

const EMPTY_FORM = {
  label: "Home", full_name: "", phone: "", address_line1: "",
  address_line2: "", city: "Daltonganj", state: "Jharkhand", pin_code: "", landmark: "",
};

export default function AddressesPage() {
  const [addresses, setAddresses] = useState<SavedAddress[]>([]);
  const [loading, setLoading] = useState(true);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState(EMPTY_FORM);
  const [saving, setSaving] = useState(false);

  useEffect(() => { fetchAddresses(); }, []);

  const fetchAddresses = async () => {
    try {
      const res = await fetch("/api/user/addresses");
      const json = await res.json();
      if (res.ok) setAddresses(json.data || []);
    } catch { /* empty */ }
    finally { setLoading(false); }
  };

  const openAdd = () => {
    setEditingId(null);
    setFormData(EMPTY_FORM);
    setDialogOpen(true);
  };

  const openEdit = (addr: SavedAddress) => {
    setEditingId(addr.id);
    setFormData({
      label: addr.label, full_name: addr.full_name, phone: addr.phone,
      address_line1: addr.address_line1, address_line2: addr.address_line2 || "",
      city: addr.city, state: addr.state, pin_code: addr.pin_code, landmark: addr.landmark || "",
    });
    setDialogOpen(true);
  };

  const handleSave = async () => {
    if (!formData.full_name || !formData.phone || !formData.address_line1 || !formData.pin_code) {
      toast.error("Fill all required fields"); return;
    }
    setSaving(true);
    try {
      const url = editingId ? `/api/user/addresses/${editingId}` : "/api/user/addresses";
      const method = editingId ? "PATCH" : "POST";
      const res = await fetch(url, { method, headers: { "Content-Type": "application/json" }, body: JSON.stringify(formData) });
      if (!res.ok) throw new Error("Failed");
      toast.success(editingId ? "Address updated" : "Address added");
      setDialogOpen(false);
      fetchAddresses();
    } catch { toast.error("Failed to save"); }
    finally { setSaving(false); }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Delete this address?")) return;
    try {
      await fetch(`/api/user/addresses/${id}`, { method: "DELETE" });
      toast.success("Address removed");
      fetchAddresses();
    } catch { toast.error("Failed"); }
  };

  const handleSetDefault = async (id: string) => {
    try {
      await fetch(`/api/user/addresses/${id}`, {
        method: "PATCH", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ is_default: true }),
      });
      toast.success("Default address updated");
      fetchAddresses();
    } catch { toast.error("Failed"); }
  };

  if (loading) {
    return <div className="min-h-screen bg-surface flex items-center justify-center"><Loader2 className="h-8 w-8 animate-spin text-botanical" /></div>;
  }

  return (
    <div className="min-h-screen bg-surface">
      <div className="container mx-auto px-4 py-6 max-w-2xl">
        <Breadcrumbs items={[{ label: "Account", href: "/account" }, { label: "Addresses" }]} />
        <div className="flex items-center justify-between mt-6 mb-6">
          <h1 className="font-heading text-3xl font-bold text-on-surface tracking-tight">My Addresses</h1>
          <button onClick={openAdd} className="px-4 py-2 rounded-full bg-botanical-gradient text-white text-sm font-medium flex items-center gap-1.5">
            <Plus className="h-4 w-4" /> Add
          </button>
        </div>

        {addresses.length === 0 ? (
          <div className="text-center py-20 bg-surface-lowest rounded-2xl shadow-ambient-sm">
            <MapPin className="h-12 w-12 mx-auto text-on-surface-variant/30 mb-3" />
            <p className="text-on-surface-variant mb-4">No saved addresses</p>
            <button onClick={openAdd} className="px-6 py-2.5 rounded-full bg-botanical-gradient text-white text-sm font-medium">Add Address</button>
          </div>
        ) : (
          <div className="space-y-3">
            {addresses.map((addr) => (
              <div key={addr.id} className={`bg-surface-lowest rounded-2xl shadow-ambient-sm p-5 relative ${addr.is_default ? "ring-2 ring-botanical/30" : ""}`}>
                {addr.is_default && (
                  <span className="absolute top-3 right-3 px-2 py-0.5 rounded-full bg-botanical/10 text-botanical text-[10px] font-semibold uppercase">Default</span>
                )}
                <div className="flex items-start gap-3">
                  <div className="h-10 w-10 rounded-full bg-surface-low flex items-center justify-center shrink-0">
                    {addr.label === "Office" ? <Building className="h-4 w-4 text-on-surface-variant" /> : <Home className="h-4 w-4 text-on-surface-variant" />}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1">
                      <span className="text-sm font-semibold text-on-surface">{addr.full_name}</span>
                      <span className="text-[10px] bg-surface-high px-2 py-0.5 rounded-full text-on-surface-variant">{addr.label}</span>
                    </div>
                    <p className="text-sm text-on-surface-variant">{addr.address_line1}</p>
                    {addr.landmark && <p className="text-xs text-on-surface-variant">Near: {addr.landmark}</p>}
                    <p className="text-sm text-on-surface-variant">{addr.city}, {addr.state} - {addr.pin_code}</p>
                    <p className="text-xs text-on-surface-variant mt-1">📞 {addr.phone}</p>
                  </div>
                </div>
                <div className="flex gap-2 mt-3 pt-3 border-t border-surface-high">
                  <button onClick={() => openEdit(addr)} className="text-xs font-medium text-botanical flex items-center gap-1 hover:underline"><Edit2 className="h-3 w-3" /> Edit</button>
                  <button onClick={() => handleDelete(addr.id)} className="text-xs font-medium text-red-500 flex items-center gap-1 hover:underline"><Trash2 className="h-3 w-3" /> Delete</button>
                  {!addr.is_default && (
                    <button onClick={() => handleSetDefault(addr.id)} className="text-xs font-medium text-on-surface-variant flex items-center gap-1 hover:underline ml-auto"><Check className="h-3 w-3" /> Set Default</button>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Add/Edit Dialog */}
        <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
          <DialogContent className="max-w-md bg-surface-lowest">
            <DialogHeader><DialogTitle className="font-heading">{editingId ? "Edit" : "Add"} Address</DialogTitle></DialogHeader>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-2">
              <div className="sm:col-span-2"><Label className="text-xs">Full Name *</Label><Input value={formData.full_name} onChange={(e) => setFormData({ ...formData, full_name: e.target.value })} className="bg-surface-high border-0 mt-1" /></div>
              <div className="sm:col-span-2"><Label className="text-xs">Phone *</Label><Input value={formData.phone} onChange={(e) => setFormData({ ...formData, phone: e.target.value })} className="bg-surface-high border-0 mt-1" /></div>
              <div className="sm:col-span-2"><Label className="text-xs">Address *</Label><Textarea value={formData.address_line1} onChange={(e) => setFormData({ ...formData, address_line1: e.target.value })} className="bg-surface-high border-0 mt-1 min-h-[60px]" /></div>
              <div><Label className="text-xs">Pin Code *</Label><Input value={formData.pin_code} onChange={(e) => setFormData({ ...formData, pin_code: e.target.value })} className="bg-surface-high border-0 mt-1" maxLength={6} /></div>
              <div><Label className="text-xs">Landmark</Label><Input value={formData.landmark} onChange={(e) => setFormData({ ...formData, landmark: e.target.value })} className="bg-surface-high border-0 mt-1" /></div>
              <div><Label className="text-xs">City</Label><Input value={formData.city} disabled className="bg-surface-high border-0 mt-1 opacity-60" /></div>
              <div><Label className="text-xs">State</Label><Input value={formData.state} disabled className="bg-surface-high border-0 mt-1 opacity-60" /></div>
              <div className="sm:col-span-2 flex gap-2">
                {["Home", "Office", "Other"].map((l) => (
                  <button key={l} onClick={() => setFormData({ ...formData, label: l })} className={`px-4 py-1.5 rounded-full text-xs font-medium transition-all ${formData.label === l ? "bg-botanical-gradient text-white" : "bg-surface-high text-on-surface-variant"}`}>{l}</button>
                ))}
              </div>
            </div>
            <button onClick={handleSave} disabled={saving} className="mt-4 w-full h-10 rounded-full bg-botanical-gradient text-white font-medium text-sm flex items-center justify-center gap-2 disabled:opacity-40">
              {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : null} {editingId ? "Update" : "Save"} Address
            </button>
          </DialogContent>
        </Dialog>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import Link from "next/link";
import {
  Package, MapPin, Phone, Copy, Shield, Truck, Store,
  CheckCircle2, Clock, Loader2, ArrowLeft,
} from "lucide-react";
import { toast } from "sonner";
import { Breadcrumbs } from "@/components/shared/breadcrumbs";
import { formatPrice, formatDate, formatStatus, getStatusColor } from "@/lib/helpers/format";

interface OrderDetail {
  id: string;
  order_number: string;
  status: string;
  subtotal: number;
  delivery_fee: number;
  discount: number;
  total: number;
  payment_method: string;
  payment_status: string;
  delivery_address: {
    full_name: string;
    phone: string;
    full_address: string;
    landmark?: string;
    pin_code: string;
    city: string;
    state: string;
  };
  delivery_otp: string;
  delivery_date: string;
  gift_message: string | null;
  special_instructions: string | null;
  created_at: string;
  order_sellers: {
    id: string;
    status: string;
    subtotal: number;
    commission_rate: number;
    seller_amount: number;
    stores: { id: string; store_name: string } | null;
    rider: { id: string; name: string; phone: string } | null;
    order_items: {
      id: string;
      product_name: string;
      product_image: string | null;
      variant_name: string | null;
      quantity: number;
      unit_price: number;
      total_price: number;
      is_reviewed: boolean;
    }[];
  }[];
}

const STATUS_STEPS = [
  { key: "placed", label: "Placed", icon: Package },
  { key: "confirmed", label: "Confirmed", icon: CheckCircle2 },
  { key: "packed", label: "Packed", icon: Store },
  { key: "out_for_delivery", label: "Out for Delivery", icon: Truck },
  { key: "delivered", label: "Delivered", icon: CheckCircle2 },
];

export default function OrderDetailPage() {
  const params = useParams();
  const orderId = params.id as string;
  const [order, setOrder] = useState<OrderDetail | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!orderId) return;
    fetchOrder();
  }, [orderId]);

  const fetchOrder = async () => {
    try {
      const res = await fetch(`/api/orders/${orderId}`);
      const json = await res.json();
      if (res.ok) setOrder(json.data);
    } catch { /* empty */ }
    finally { setLoading(false); }
  };

  const copyOtp = async (otp: string) => {
    try {
      await navigator.clipboard.writeText(otp);
      toast.success("OTP copied!");
    } catch { /* empty */ }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-surface flex items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-botanical" />
      </div>
    );
  }

  if (!order) {
    return (
      <div className="min-h-screen bg-surface flex items-center justify-center">
        <div className="text-center space-y-4">
          <p className="text-on-surface-variant">Order not found</p>
          <Link href="/account/orders" className="inline-block px-6 py-2.5 rounded-full bg-botanical-gradient text-white text-sm font-medium">
            Back to Orders
          </Link>
        </div>
      </div>
    );
  }

  // Get the highest sub-order status for timeline
  const getStatusIndex = (status: string) => STATUS_STEPS.findIndex((s) => s.key === status);
  const overallStatusIdx = order.status === "delivered" ? 4 : order.status === "cancelled" ? -1 : getStatusIndex(order.status);
  const addr = order.delivery_address;

  return (
    <div className="min-h-screen bg-surface">
      <div className="container mx-auto px-4 py-6 max-w-4xl">
        <Breadcrumbs items={[{ label: "Account", href: "/account" }, { label: "Orders", href: "/account/orders" }, { label: order.order_number }]} />

        <div className="flex items-center gap-3 mt-6 mb-6">
          <Link href="/account/orders" className="p-2 rounded-full hover:bg-surface-low transition-colors">
            <ArrowLeft className="h-5 w-5 text-on-surface-variant" />
          </Link>
          <div>
            <h1 className="font-heading text-2xl font-bold text-on-surface">{order.order_number}</h1>
            <p className="text-xs text-on-surface-variant">{formatDate(order.created_at)}</p>
          </div>
          <span className={`ml-auto px-3 py-1 rounded-full text-xs font-semibold uppercase tracking-wider ${getStatusColor(order.status)}`}>
            {formatStatus(order.status)}
          </span>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="lg:col-span-2 space-y-4">

            {/* Status Timeline */}
            {order.status !== "cancelled" && (
              <div className="bg-surface-lowest rounded-2xl shadow-ambient-sm p-5 sm:p-6">
                <h3 className="font-heading font-semibold text-on-surface mb-5">Order Progress</h3>
                <div className="flex items-center justify-between relative">
                  {/* Line */}
                  <div className="absolute top-4 left-6 right-6 h-0.5 bg-surface-high" />
                  <div className="absolute top-4 left-6 h-0.5 bg-botanical transition-all" style={{ width: `${Math.max(0, overallStatusIdx) * 25}%` }} />

                  {STATUS_STEPS.map((step, idx) => {
                    const done = idx <= overallStatusIdx;
                    const Icon = step.icon;
                    return (
                      <div key={step.key} className="relative z-10 flex flex-col items-center">
                        <div className={`h-8 w-8 rounded-full flex items-center justify-center transition-all ${done ? "bg-botanical-gradient text-white shadow-ambient-sm" : "bg-surface-high text-on-surface-variant/40"}`}>
                          <Icon className="h-4 w-4" />
                        </div>
                        <span className={`text-[10px] mt-2 font-medium ${done ? "text-botanical" : "text-on-surface-variant/50"}`}>
                          {step.label}
                        </span>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {/* Sub-orders */}
            {order.order_sellers.map((subOrder, idx) => (
              <div key={subOrder.id} className="bg-surface-lowest rounded-2xl shadow-ambient-sm p-5 sm:p-6">
                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center gap-2">
                    <Store className="h-4 w-4 text-on-surface-variant" />
                    <span className="text-sm font-medium text-on-surface">
                      {subOrder.stores?.store_name || "Seller"}
                    </span>
                  </div>
                  <span className={`px-2 py-0.5 rounded-full text-[10px] font-semibold uppercase tracking-wider ${getStatusColor(subOrder.status)}`}>
                    {formatStatus(subOrder.status)}
                  </span>
                </div>

                {/* Items */}
                <div className="space-y-3">
                  {subOrder.order_items.map((item) => (
                    <div key={item.id} className="flex gap-3">
                      <div className="h-14 w-14 rounded-xl bg-surface-low overflow-hidden shrink-0">
                        {item.product_image ? (
                          <img src={item.product_image} alt={item.product_name} className="h-full w-full object-cover" />
                        ) : (
                          <div className="h-full w-full flex items-center justify-center"><Package className="h-5 w-5 text-on-surface-variant/30" /></div>
                        )}
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium text-on-surface truncate">{item.product_name}</p>
                        {item.variant_name && <p className="text-xs text-on-surface-variant">{item.variant_name}</p>}
                        <div className="flex items-center justify-between mt-1">
                          <span className="text-xs text-on-surface-variant">Qty: {item.quantity}</span>
                          <span className="text-sm font-medium text-on-surface">{formatPrice(item.total_price)}</span>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>

                {/* Rider info */}
                {subOrder.rider && (subOrder.status === "out_for_delivery" || subOrder.status === "picked_up") && (
                  <div className="mt-4 p-3 bg-blue-50 dark:bg-blue-950/20 rounded-xl flex items-center gap-3">
                    <Truck className="h-5 w-5 text-blue-600" />
                    <div className="flex-1">
                      <p className="text-sm font-medium text-blue-800 dark:text-blue-300">{subOrder.rider.name}</p>
                      <p className="text-xs text-blue-600 dark:text-blue-400">Your delivery rider</p>
                    </div>
                    <a href={`tel:${subOrder.rider.phone}`} className="p-2 rounded-full bg-blue-100 dark:bg-blue-900/30">
                      <Phone className="h-4 w-4 text-blue-600" />
                    </a>
                  </div>
                )}
              </div>
            ))}
          </div>

          {/* Sidebar */}
          <div className="space-y-4">
            {/* Delivery OTP */}
            {order.delivery_otp && order.status !== "delivered" && order.status !== "cancelled" && (
              <div className="bg-amber-50 dark:bg-amber-950/30 rounded-2xl p-5 text-center space-y-2">
                <div className="flex items-center justify-center gap-2">
                  <Shield className="h-4 w-4 text-amber-600" />
                  <span className="text-xs font-semibold text-amber-700 dark:text-amber-400 uppercase tracking-wider">Delivery OTP</span>
                </div>
                <p className="font-mono text-2xl font-bold tracking-[0.3em] text-amber-800 dark:text-amber-300">
                  ••••••
                </p>
                <p className="text-[10px] text-amber-600">Check SMS for OTP</p>
              </div>
            )}

            {/* Address */}
            <div className="bg-surface-lowest rounded-2xl shadow-ambient-sm p-5">
              <div className="flex items-center gap-2 mb-3">
                <MapPin className="h-4 w-4 text-botanical" />
                <span className="text-sm font-semibold text-on-surface">Delivery Address</span>
              </div>
              <div className="text-sm text-on-surface-variant space-y-0.5">
                <p className="font-medium text-on-surface">{addr.full_name}</p>
                <p>{addr.full_address}</p>
                {addr.landmark && <p>Near: {addr.landmark}</p>}
                <p>{addr.city}, {addr.state} - {addr.pin_code}</p>
                <p>📞 {addr.phone}</p>
              </div>
            </div>

            {/* Price Summary */}
            <div className="bg-surface-lowest rounded-2xl shadow-ambient-sm p-5 space-y-3">
              <h4 className="font-heading font-semibold text-on-surface">Payment Details</h4>
              <div className="space-y-2 text-sm">
                <div className="flex justify-between">
                  <span className="text-on-surface-variant">Subtotal</span>
                  <span className="text-on-surface">{formatPrice(order.subtotal)}</span>
                </div>
                {order.discount > 0 && (
                  <div className="flex justify-between text-green-600">
                    <span>Discount</span>
                    <span>-{formatPrice(order.discount)}</span>
                  </div>
                )}
                <div className="flex justify-between">
                  <span className="text-on-surface-variant">Delivery</span>
                  <span className={order.delivery_fee === 0 ? "text-botanical" : "text-on-surface"}>
                    {order.delivery_fee === 0 ? "FREE" : formatPrice(order.delivery_fee)}
                  </span>
                </div>
                <div className="h-px bg-surface-high" />
                <div className="flex justify-between font-semibold">
                  <span>Total</span>
                  <span className="text-botanical">{formatPrice(order.total)}</span>
                </div>
              </div>
              <div className="pt-2 flex items-center gap-2 text-xs text-on-surface-variant">
                <span className="uppercase font-medium">{order.payment_method}</span>
                <span>•</span>
                <span className={`${getStatusColor(order.payment_status)} px-2 py-0.5 rounded-full text-[10px] font-semibold`}>
                  {formatStatus(order.payment_status)}
                </span>
              </div>
            </div>
          </div>
        </div>
      </div>
