                <div className="flex gap-2 mt-1 flex-wrap">
                  {BUDGETS.map((b) => (
                    <button key={b} onClick={() => setForm({ ...form, budget: b })} className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${form.budget === b ? "bg-botanical-gradient text-white" : "bg-surface-high text-on-surface-variant"}`}>
                      {b}
                    </button>
                  ))}
                </div>
              </div>

              <div className="sm:col-span-2"><Label className="text-xs">Requirements / Notes</Label><Textarea value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })} placeholder="Describe your vision..." className="bg-surface-high border-0 mt-1 min-h-[80px]" /></div>
            </div>

            <button onClick={handleSubmit} disabled={isSubmitting} className="mt-6 w-full h-12 rounded-full bg-botanical-gradient text-white font-medium text-sm flex items-center justify-center gap-2 shadow-ambient-sm hover:shadow-ambient transition-shadow disabled:opacity-40">
              {isSubmitting ? <><Loader2 className="h-4 w-4 animate-spin" /> Submitting...</> : <>Submit Request <ArrowRight className="h-4 w-4" /></>}
            </button>
          </div>
        </section>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import Link from "next/link";
import { Heart, ShoppingCart, Store, Truck, Shield } from "lucide-react";
import { toast } from "sonner";
import { Badge } from "@/components/ui/badge";
import { ImageGallery } from "@/components/shared/image-gallery";
import { PriceDisplay } from "@/components/shared/price-display";
import { RatingStars } from "@/components/shared/rating-stars";
import { QuantitySelector } from "@/components/shared/quantity-selector";
import { ProductGrid } from "@/components/shared/product-grid";
import { useCartStore } from "@/stores/cart-store";
import type { ProductCardData } from "@/types";

interface ProductDetailProps {
  product: Record<string, unknown>;
  relatedProducts: Record<string, unknown>[];
}

export default function ProductDetailClient({ product, relatedProducts }: ProductDetailProps) {
  const [quantity, setQuantity] = useState(1);
  const [selectedVariant, setSelectedVariant] = useState<string | null>(null);
  const addItem = useCartStore((s) => s.addItem);

  const images = (product.product_images as { image_url: string; is_primary: boolean; sort_order: number }[]) || [];
  const variants = (product.product_variants as { id: string; variant_name: string; price: number; sale_price: number | null; stock_qty: number }[]) || [];
  const store = product.stores as { id: string; store_name: string; slug: string; rating: number } | null;

  const activeVariant = variants.find((v) => v.id === selectedVariant);
  const displayPrice = activeVariant ? activeVariant.price : (product.price as number);
  const displaySalePrice = activeVariant?.sale_price ?? (product.sale_price as number | null);
  const inStock = activeVariant ? activeVariant.stock_qty > 0 : (product.stock_qty as number) > 0;

  const handleAddToCart = () => {
    addItem({
      product_id: product.id as string,
      variant_id: selectedVariant,
      quantity,
      price: displaySalePrice && displaySalePrice < displayPrice ? displaySalePrice : displayPrice,
      name: product.name as string,
      image: images.find((i) => i.is_primary)?.image_url || images[0]?.image_url || null,
      store_id: store?.id || "",
      store_name: store?.store_name || "",
    });
    toast.success("Added to cart! 🌿");
  };

  const relatedItems: ProductCardData[] = relatedProducts.map((p) => ({
    id: p.id as string, name: p.name as string, slug: p.slug as string,
    price: p.price as number, sale_price: p.sale_price as number | null,
    avg_rating: (p.avg_rating as number) ?? 0, total_reviews: (p.total_reviews as number) ?? 0,
    is_featured: (p.is_featured as boolean) ?? false, store_id: p.store_id as string,
    primary_image: (p.product_images as { image_url: string; is_primary: boolean }[])?.find((i) => i.is_primary)?.image_url || null,
    store_name: (p.stores as unknown as { store_name: string })?.store_name || null,
  }));

  return (
    <div className="min-h-screen bg-surface">
      <div className="container mx-auto px-4 py-6 max-w-7xl">
        <div className="mt-6 grid grid-cols-1 lg:grid-cols-2 gap-8 lg:gap-16">
          {/* Gallery */}
          <div className="bg-surface-lowest rounded-2xl p-4 shadow-ambient-sm">
            <ImageGallery images={images} productName={product.name as string} />
          </div>

          {/* Product Info */}
          <div className="space-y-6">
            <div>
              <h1 className="font-heading text-2xl md:text-3xl font-bold text-on-surface tracking-tight leading-tight">
                {product.name as string}
              </h1>
              {store && (
                <Link
                  href={`/store/${store.slug}`}
                  className="inline-flex items-center gap-1.5 text-sm text-on-surface-variant hover:text-botanical transition-colors mt-2"
                >
                  <Store className="h-3.5 w-3.5" />
                  {store.store_name}
                </Link>
              )}
            </div>

            {/* Rating */}
            {(product.avg_rating as number) > 0 && (
              <RatingStars rating={product.avg_rating as number} showValue totalReviews={product.total_reviews as number} />
            )}

            {/* Price */}
            <PriceDisplay price={displayPrice} salePrice={displaySalePrice} size="lg" />

            {/* Variants */}
            {variants.length > 0 && (
              <div className="space-y-3">
                <p className="font-heading text-sm font-semibold text-on-surface tracking-wide uppercase">Variants</p>
                <div className="flex flex-wrap gap-2">
                  {variants.map((v) => (
                    <button
                      key={v.id}
                      type="button"
                      onClick={() => setSelectedVariant(selectedVariant === v.id ? null : v.id)}
                      className={`px-4 py-2 rounded-full text-sm font-medium transition-all ${
                        selectedVariant === v.id
                          ? "bg-botanical-gradient text-white shadow-ambient-sm"
                          : "bg-surface-high text-on-surface-variant hover:bg-surface-highest"
                      } ${v.stock_qty === 0 ? "opacity-40 line-through cursor-not-allowed" : ""}`}
                      disabled={v.stock_qty === 0}
                    >
                      {v.variant_name}
                    </button>
                  ))}
                </div>
              </div>
            )}

            {/* Quantity + Cart */}
            <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-3 pt-2">
              <QuantitySelector value={quantity} onChange={setQuantity} max={product.stock_qty as number} />
              <button
                className="flex-1 h-12 rounded-full bg-botanical-gradient text-white font-medium text-sm flex items-center justify-center gap-2 shadow-ambient-sm hover:shadow-ambient transition-shadow disabled:opacity-40"
                onClick={handleAddToCart}
                disabled={!inStock}
              >
                <ShoppingCart className="h-4 w-4" />
                {inStock ? "Add to Cart" : "Out of Stock"}
              </button>
              <button className="h-12 w-12 rounded-full bg-surface-lowest shadow-ambient-sm flex items-center justify-center shrink-0 hover:shadow-ambient transition-shadow">
                <Heart className="h-5 w-5 text-on-surface-variant" />
              </button>
            </div>

            {/* Trust Badges */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              <div className="flex items-center gap-3 p-4 rounded-xl bg-surface-low">
                <div className="h-9 w-9 rounded-full bg-botanical-gradient flex items-center justify-center shrink-0">
                  <Truck className="h-4 w-4 text-white" />
                </div>
                <div>
                  <p className="text-xs font-medium text-on-surface">Same-day delivery</p>
                  <p className="text-xs text-on-surface-variant">In Daltonganj</p>
                </div>
              </div>
              <div className="flex items-center gap-3 p-4 rounded-xl bg-surface-low">
                <div className="h-9 w-9 rounded-full bg-botanical-gradient flex items-center justify-center shrink-0">
                  <Shield className="h-4 w-4 text-white" />
                </div>
                <div>
                  <p className="text-xs font-medium text-on-surface">Fresh guarantee</p>
                  <p className="text-xs text-on-surface-variant">7-day return</p>
                </div>
              </div>
            </div>

            {/* Description */}
            {(product.description as string) && (
              <div className="space-y-2 pt-2">
                <h3 className="font-heading font-semibold text-on-surface">Description</h3>
                <p className="text-sm text-on-surface-variant leading-relaxed whitespace-pre-wrap">
                  {product.description as string}
                </p>
              </div>
            )}

            {/* Care */}
            {(product.care_instructions as string) && (
              <div className="space-y-2">
                <h3 className="font-heading font-semibold text-on-surface">Care Instructions</h3>
                <p className="text-sm text-on-surface-variant leading-relaxed whitespace-pre-wrap">
                  {product.care_instructions as string}
                </p>
              </div>
            )}

            {/* Tags */}
            {(product.tags as string[])?.length > 0 && (
              <div className="flex flex-wrap gap-2">
                {(product.tags as string[]).map((tag) => (
                  <span key={tag} className="px-3 py-1 rounded-full bg-surface-highest text-on-surface-variant text-xs font-medium">
                    {tag}
                  </span>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Related */}
        {relatedItems.length > 0 && (
          <div className="mt-20">
            <h2 className="font-heading text-2xl font-bold text-on-surface mb-8">You May Also Love</h2>
            <ProductGrid products={relatedItems} columns={4} />
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState, Suspense } from "react";
import { useSearchParams } from "next/navigation";
import { Search } from "lucide-react";
import { Breadcrumbs } from "@/components/shared/breadcrumbs";
import { ProductGrid } from "@/components/shared/product-grid";
import { LoadingSpinner } from "@/components/shared/loading-spinner";
import { EmptyState } from "@/components/shared/empty-state";
import type { ProductCardData } from "@/types";

function SearchResultsContent() {
  const searchParams = useSearchParams();
  const q = searchParams.get("q") || "";
  const [products, setProducts] = useState<ProductCardData[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (!q) { setProducts([]); setIsLoading(false); return; }
    setIsLoading(true);
    fetch(`/api/search?q=${encodeURIComponent(q)}`)
      .then((r) => r.json())
      .then((json) => {
        const items: ProductCardData[] = (json.data || []).map(
          (p: Record<string, unknown>) => ({
            id: p.id, name: p.name, slug: p.slug, price: p.price,
            sale_price: p.sale_price, avg_rating: (p.avg_rating as number) ?? 0,
            total_reviews: (p.total_reviews as number) ?? 0,
            is_featured: (p.is_featured as boolean) ?? false,
            store_id: p.store_id,
            primary_image: (p.product_images as { image_url: string; is_primary: boolean }[])?.find((i) => i.is_primary)?.image_url || null,
            store_name: (p.stores as unknown as { store_name: string })?.store_name || null,
          })
        );
        setProducts(items);
      })
      .catch(() => {})
      .finally(() => setIsLoading(false));
  }, [q]);

  return (
    <div className="min-h-screen bg-surface">
      <div className="container mx-auto px-4 py-6 max-w-7xl">
        <Breadcrumbs items={[{ label: "Shop", href: "/shop" }, { label: "Search" }]} />

        <div className="mt-6 mb-8">
          <div className="flex items-center gap-3">
            <div className="h-10 w-10 rounded-full bg-botanical-gradient flex items-center justify-center">
              <Search className="h-5 w-5 text-white" />
            </div>
            <div>
              <h1 className="font-heading text-2xl md:text-3xl font-bold text-on-surface tracking-tight">
                Search Results
              </h1>
              {q && (
                <p className="text-sm text-on-surface-variant mt-0.5">
                  {products.length} {products.length === 1 ? "result" : "results"} for &ldquo;{q}&rdquo;
                </p>
              )}
            </div>
          </div>
        </div>

        {isLoading ? (
          <div className="py-20"><LoadingSpinner text="Searching..." /></div>
        ) : products.length > 0 ? (
          <ProductGrid products={products} columns={4} />
        ) : (
          <div className="mt-8">
            <EmptyState
              icon={Search}
              title={`No products found for "${q}"`}
              description="Try different search terms or browse our collection"
              actionLabel="Browse Collection"
              onAction={() => window.location.href = "/shop"}
            />
          </div>
        )}
      </div>
    </div>
  );
}

export default function SearchPage() {
  return (
    <Suspense fallback={<div className="min-h-screen bg-surface py-20"><LoadingSpinner text="Loading..." /></div>}>
      <SearchResultsContent />
    </Suspense>
  );
}

"use client";

import { useEffect, useState, useCallback } from "react";
import { useSearchParams, useRouter } from "next/navigation";
import { SlidersHorizontal, X, ChevronDown } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from "@/components/ui/sheet";
import { Checkbox } from "@/components/ui/checkbox";
import { ProductGrid } from "@/components/shared/product-grid";
import { LoadingSpinner } from "@/components/shared/loading-spinner";
import { Breadcrumbs } from "@/components/shared/breadcrumbs";
import { PRODUCTS_PER_PAGE, OCCASIONS } from "@/lib/constants";
import type { ProductCardData, Category } from "@/types";

export default function ShopPageClient() {
  const router = useRouter();
  const searchParams = useSearchParams();

  const [products, setProducts] = useState<ProductCardData[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [totalCount, setTotalCount] = useState(0);

  const page = parseInt(searchParams.get("page") || "1");
  const categorySlug = searchParams.get("category") || "";
  const occasion = searchParams.get("occasion") || "";
  const sortBy = searchParams.get("sort") || "created_at";
  const sortOrder = searchParams.get("order") || "desc";
  const minPrice = searchParams.get("min_price") || "";
  const maxPrice = searchParams.get("max_price") || "";

  const updateFilters = useCallback(
    (updates: Record<string, string>) => {
      const params = new URLSearchParams(searchParams.toString());
      for (const [key, val] of Object.entries(updates)) {
        if (val) params.set(key, val);
        else params.delete(key);
      }
      if (!updates.page) params.set("page", "1");
      router.push(`/shop?${params.toString()}`);
    },
    [searchParams, router]
  );

  useEffect(() => {
    fetch("/api/categories")
      .then((r) => r.json())
      .then((json) => {
        if (json.data) {
          const flat: Category[] = [];
          for (const p of json.data) {
            flat.push(p);
            if (p.children) flat.push(...p.children);
          }
          setCategories(flat);
        }
      })
      .catch(() => {});
  }, []);

  useEffect(() => {
    const fetchProducts = async () => {
      setIsLoading(true);
      try {
        const params = new URLSearchParams();
        params.set("page", String(page));
        params.set("pageSize", String(PRODUCTS_PER_PAGE));
        params.set("status", "active");
        params.set("sort_by", sortBy);
        params.set("sort_order", sortOrder);
        if (categorySlug) {
          const cat = categories.find((c) => c.slug === categorySlug);
          if (cat) params.set("category_id", cat.id);
        }
        const res = await fetch(`/api/products?${params.toString()}`);
        const json = await res.json();
        if (res.ok) {
          const items: ProductCardData[] = (json.data || []).map(
            (p: Record<string, unknown>) => ({
              id: p.id, name: p.name, slug: p.slug, price: p.price,
              sale_price: p.sale_price, avg_rating: (p.avg_rating as number) ?? 0,
              total_reviews: (p.total_reviews as number) ?? 0,
              is_featured: (p.is_featured as boolean) ?? false,
              store_id: p.store_id,
              primary_image: (p.product_images as { image_url: string; is_primary: boolean }[])?.find((i) => i.is_primary)?.image_url || null,
              store_name: (p.stores as { store_name: string } | null)?.store_name || null,
            })
          );
          setProducts(items);
          setTotalCount(json.count || 0);
        }
      } catch { /* silent */ } finally { setIsLoading(false); }
    };
    fetchProducts();
  }, [page, categorySlug, occasion, sortBy, sortOrder, categories, minPrice, maxPrice]);

  const totalPages = Math.ceil(totalCount / PRODUCTS_PER_PAGE);
  const hasActiveFilters = !!(categorySlug || occasion || minPrice || maxPrice);

  const FilterContent = () => (
    <div className="space-y-8">
      {/* Categories */}
      <div className="space-y-3">
        <p className="font-heading text-sm font-semibold text-on-surface tracking-wide uppercase">Categories</p>
        {categories.filter((c) => !c.parent_id).map((cat) => (
          <label key={cat.id} className="flex items-center gap-3 cursor-pointer group">
            <Checkbox
              checked={categorySlug === cat.slug}
              onCheckedChange={(checked) => updateFilters({ category: checked ? cat.slug : "" })}
            />
            <span className="text-sm text-on-surface-variant group-hover:text-botanical transition-colors">{cat.name}</span>
          </label>
        ))}
      </div>

      {/* Occasion */}
      <div className="space-y-3">
        <p className="font-heading text-sm font-semibold text-on-surface tracking-wide uppercase">Occasion</p>
        {OCCASIONS.map((o) => (
          <label key={o} className="flex items-center gap-3 cursor-pointer group">
            <Checkbox
              checked={occasion === o}
              onCheckedChange={(checked) => updateFilters({ occasion: checked ? o : "" })}
            />
            <span className="text-sm text-on-surface-variant group-hover:text-botanical transition-colors">{o}</span>
          </label>
        ))}
      </div>

      {/* Price */}
      <div className="space-y-3">
        <p className="font-heading text-sm font-semibold text-on-surface tracking-wide uppercase">Price Range</p>
        <div className="flex items-center gap-2">
          <Input type="number" placeholder="Min ₹" value={minPrice} onChange={(e) => updateFilters({ min_price: e.target.value })} className="bg-surface-high border-0 text-sm h-9" />
          <span className="text-on-surface-variant text-xs">to</span>
          <Input type="number" placeholder="Max ₹" value={maxPrice} onChange={(e) => updateFilters({ max_price: e.target.value })} className="bg-surface-high border-0 text-sm h-9" />
        </div>
      </div>

      {hasActiveFilters && (
        <button
          onClick={() => updateFilters({ category: "", occasion: "", min_price: "", max_price: "" })}
          className="flex items-center gap-1.5 text-sm text-red-500 hover:text-red-600 transition-colors"
        >
          <X className="h-3.5 w-3.5" />Clear All Filters
        </button>
      )}
    </div>
  );

  return (
    <div className="min-h-screen bg-surface">
      <div className="container mx-auto px-4 py-6 max-w-7xl">
        <Breadcrumbs items={[{ label: "Shop" }]} />

        {/* Header */}
        <div className="flex items-end justify-between mt-6 mb-8">
          <div>
            <h1 className="font-heading text-3xl md:text-4xl font-bold text-on-surface tracking-tight">
              The Collection
            </h1>
            <p className="text-sm text-on-surface-variant mt-1.5">
              {totalCount} curated specimens
            </p>
          </div>
          <div className="flex items-center gap-3">
            {/* Mobile filter */}
            <Sheet>
              <SheetTrigger className="inline-flex items-center gap-2 text-sm font-medium px-4 py-2 rounded-full bg-surface-lowest shadow-ambient-sm lg:hidden hover:shadow-ambient transition-shadow">
                <SlidersHorizontal className="h-4 w-4" />Filters
                {hasActiveFilters && <span className="h-2 w-2 rounded-full bg-botanical-primary" />}
              </SheetTrigger>
              <SheetContent side="left" className="w-[300px] bg-surface-low">
                <SheetHeader><SheetTitle className="font-heading">Refine</SheetTitle></SheetHeader>
                <div className="mt-6"><FilterContent /></div>
              </SheetContent>
            </Sheet>

            {/* Sort */}
            <Select value={`${sortBy}-${sortOrder}`} onValueChange={(val) => { if (!val) return; const [sb, so] = val.split("-"); updateFilters({ sort: sb, order: so }); }}>
              <SelectTrigger className="w-[180px] h-10 rounded-full bg-surface-lowest shadow-ambient-sm border-0 text-sm">
                <SelectValue placeholder="Sort by" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="created_at-desc">Newest First</SelectItem>
                <SelectItem value="price-asc">Price: Low to High</SelectItem>
                <SelectItem value="price-desc">Price: High to Low</SelectItem>
                <SelectItem value="avg_rating-desc">Highest Rated</SelectItem>
                <SelectItem value="name-asc">Name: A-Z</SelectItem>
              </SelectContent>
            </Select>
          </div>
        </div>

        <div className="flex gap-10">
          {/* Desktop Sidebar */}
          <aside className="hidden lg:block w-64 shrink-0">
            <div className="sticky top-24 bg-surface-lowest rounded-2xl p-6 shadow-ambient-sm">
              <h3 className="font-heading font-semibold text-on-surface mb-6">Refine</h3>
              <FilterContent />
            </div>
          </aside>

          {/* Product Grid */}
          <main className="flex-1 min-w-0">
            {isLoading ? (
              <div className="py-20"><LoadingSpinner text="Loading collection..." /></div>
            ) : (
              <>
                <ProductGrid products={products} columns={3} />
                {totalPages > 1 && (
                  <div className="flex items-center justify-center gap-3 mt-10">
                    <button
                      disabled={page <= 1}
                      onClick={() => updateFilters({ page: String(page - 1) })}
                      className="px-5 py-2.5 rounded-full bg-surface-lowest shadow-ambient-sm text-sm font-medium text-on-surface disabled:opacity-40 hover:shadow-ambient transition-shadow"
                    >
                      Previous
                    </button>
                    <span className="text-sm text-on-surface-variant px-4">
                      Page {page} of {totalPages}
                    </span>
                    <button
                      disabled={page >= totalPages}
                      onClick={() => updateFilters({ page: String(page + 1) })}
                      className="px-5 py-2.5 rounded-full bg-surface-lowest shadow-ambient-sm text-sm font-medium text-on-surface disabled:opacity-40 hover:shadow-ambient transition-shadow"
                    >
                      Next
                    </button>
                  </div>
                )}
              </>
            )}
          </main>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState, useCallback } from "react";
import Link from "next/link";
import { Image as ImageIcon, Layout, Plus, CheckCircle2, XCircle, ExternalLink } from "lucide-react";
import { toast } from "sonner";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { LoadingSpinner } from "@/components/shared/loading-spinner";
import { EmptyState } from "@/components/shared/empty-state";

interface Banner {
  id: string;
  title: string | null;
  image_url: string;
  link_url: string | null;
  position: string;
  sort_order: number;
  is_active: boolean;
  starts_at: string | null;
  ends_at: string | null;
  created_at: string;
}

const positionColors: Record<string, string> = {
  hero: "bg-purple-100 text-purple-700 border-purple-200",
  middle: "bg-blue-100 text-blue-700 border-blue-200",
  bottom: "bg-gray-100 text-gray-700 border-gray-200",
};

export default function AdminCMSPage() {
  const [banners, setBanners] = useState<Banner[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const fetchData = useCallback(async () => {
    setIsLoading(true);
    try {
      const res = await fetch("/api/admin/banners");
      const json = await res.json();
      if (res.ok) setBanners(json.banners);
      else toast.error(json.error || "Failed to load banners");
    } catch { toast.error("Failed to load"); }
    finally { setIsLoading(false); }
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  const heroBanners = banners.filter((b) => b.position === "hero");
  const middleBanners = banners.filter((b) => b.position === "middle");
  const bottomBanners = banners.filter((b) => b.position === "bottom");

  return (
    <div className="space-y-6 max-w-7xl mx-auto pb-12">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold font-serif text-gray-900 tracking-tight">Content Management</h1>
          <p className="text-sm text-muted-foreground mt-1">Manage banners and marketing content</p>
        </div>
        <Link href="/admin/cms/banners">
          <Button className="bg-emerald-600 hover:bg-emerald-700 text-white">
            <Plus className="h-4 w-4 mr-2" />Add Banner
          </Button>
        </Link>
      </div>

      <div className="grid gap-4 grid-cols-3">
        <Card className="shadow-sm"><CardContent className="p-4 text-center">
          <p className="text-3xl font-bold text-gray-900">{banners.length}</p>
          <p className="text-xs text-muted-foreground">Total Banners</p>
        </CardContent></Card>
        <Card className="shadow-sm"><CardContent className="p-4 text-center">
          <p className="text-3xl font-bold text-emerald-600">{banners.filter((b) => b.is_active).length}</p>
          <p className="text-xs text-muted-foreground">Active</p>
        </CardContent></Card>
        <Card className="shadow-sm"><CardContent className="p-4 text-center">
          <p className="text-3xl font-bold text-purple-600">{heroBanners.length}</p>
          <p className="text-xs text-muted-foreground">Hero Banners</p>
        </CardContent></Card>
      </div>

      {isLoading ? (
        <LoadingSpinner text="Loading banners..." className="h-64" />
      ) : banners.length === 0 ? (
        <EmptyState icon={Layout} title="No banners" description="Add your first banner to showcase on the storefront." />
      ) : (
        <div className="space-y-6">
          {[
            { label: "Hero", items: heroBanners },
            { label: "Middle", items: middleBanners },
            { label: "Bottom", items: bottomBanners },
          ].map((section) => section.items.length > 0 && (
            <div key={section.label}>
              <h3 className="text-sm font-semibold text-gray-500 uppercase tracking-wider mb-3">{section.label} Banners</h3>
              <div className="grid gap-4 grid-cols-1 md:grid-cols-2 lg:grid-cols-3">
                {section.items.map((banner) => (
                  <Card key={banner.id} className={`shadow-sm overflow-hidden ${!banner.is_active ? "opacity-60" : ""}`}>
                    <div className="h-36 bg-gray-100 relative">
                      {/* eslint-disable-next-line @next/next/no-img-element */}
                      <img src={banner.image_url} alt={banner.title || "Banner"} className="w-full h-full object-cover" />
                      <div className="absolute top-2 right-2 flex gap-1">
                        <Badge variant="outline" className={`px-2 py-0.5 rounded-full text-[10px] ${positionColors[banner.position] || positionColors.hero}`}>
                          {banner.position}
                        </Badge>
                        {banner.is_active ? (
                          <Badge variant="outline" className="bg-emerald-100 text-emerald-700 border-emerald-200 text-[10px] px-2 py-0.5 rounded-full">
                            <CheckCircle2 className="h-3 w-3 mr-0.5" />Active
                          </Badge>
                        ) : (
                          <Badge variant="outline" className="bg-gray-100 text-gray-700 border-gray-200 text-[10px] px-2 py-0.5 rounded-full">
                            <XCircle className="h-3 w-3 mr-0.5" />Inactive
                          </Badge>
                        )}
                      </div>
                    </div>
                    <CardContent className="p-3">
                      <p className="font-semibold text-sm text-gray-900 truncate">{banner.title || "Untitled"}</p>
                      <div className="flex items-center justify-between mt-1 text-[10px] text-muted-foreground">
                        <span>Order: {banner.sort_order}</span>
                        {banner.link_url && (
                          <span className="flex items-center gap-0.5"><ExternalLink className="h-3 w-3" />Has link</span>
                        )}
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState, useCallback } from "react";
import {
  Ticket,
  Plus,
  Percent,
  DollarSign,
  Calendar,
  Users,
  Tag,
  CheckCircle2,
  XCircle,
} from "lucide-react";
import { toast } from "sonner";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { LoadingSpinner } from "@/components/shared/loading-spinner";
import { EmptyState } from "@/components/shared/empty-state";
import { formatCurrency } from "@/lib/utils";

interface Coupon {
  id: string;
  code: string;
  type: "percentage" | "fixed";
  value: number;
  min_order_amount: number | null;
  max_discount: number | null;
  valid_from: string | null;
  valid_to: string | null;
  usage_limit: number | null;
  per_user_limit: number;
  used_count: number;
  applicable_to: string;
  category_name: string | null;
  is_active: boolean;
  created_at: string;
}

export default function AdminCouponsPage() {
  const [coupons, setCoupons] = useState<Coupon[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [saving, setSaving] = useState(false);

  // Form state
  const [code, setCode] = useState("");
  const [type, setType] = useState<"percentage" | "fixed">("percentage");
  const [value, setValue] = useState("");
  const [minOrder, setMinOrder] = useState("");
  const [maxDiscount, setMaxDiscount] = useState("");
  const [validFrom, setValidFrom] = useState("");
  const [validTo, setValidTo] = useState("");
  const [usageLimit, setUsageLimit] = useState("");
  const [perUserLimit, setPerUserLimit] = useState("1");

  const fetchCoupons = useCallback(async () => {
    setIsLoading(true);
    try {
      const res = await fetch("/api/admin/coupons");
      const json = await res.json();
      if (res.ok) {
        setCoupons(json.coupons);
      } else {
        toast.error(json.error || "Failed to load coupons");
      }
    } catch {
      toast.error("Failed to load coupons");
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchCoupons();
  }, [fetchCoupons]);

  const resetForm = () => {
    setCode("");
    setType("percentage");
    setValue("");
    setMinOrder("");
    setMaxDiscount("");
    setValidFrom("");
    setValidTo("");
    setUsageLimit("");
    setPerUserLimit("1");
  };

  const handleCreate = async () => {
    if (!code.trim() || !value) {
      toast.error("Code and value are required");
      return;
    }

    setSaving(true);
    try {
      const payload: Record<string, unknown> = {
        code: code.trim().toUpperCase(),
        type,
        value: parseFloat(value),
        per_user_limit: parseInt(perUserLimit, 10) || 1,
      };
      if (minOrder) payload.min_order_amount = parseFloat(minOrder);
      if (maxDiscount) payload.max_discount = parseFloat(maxDiscount);
      if (validFrom) payload.valid_from = new Date(validFrom).toISOString();
      if (validTo) payload.valid_to = new Date(validTo).toISOString();
      if (usageLimit) payload.usage_limit = parseInt(usageLimit, 10);

      const res = await fetch("/api/admin/coupons", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });
      const json = await res.json();

      if (res.ok) {
        toast.success("Coupon created successfully");
        setDialogOpen(false);
        resetForm();
        fetchCoupons();
      } else {
        toast.error(json.error || "Failed to create coupon");
      }
    } catch {
      toast.error("Failed to create coupon");
    } finally {
      setSaving(false);
    }
  };

  const isExpired = (coupon: Coupon) => {
    if (!coupon.valid_to) return false;
    return new Date(coupon.valid_to) < new Date();
  };

  const isExhausted = (coupon: Coupon) => {
    if (!coupon.usage_limit) return false;
    return coupon.used_count >= coupon.usage_limit;
  };

  return (
    <div className="space-y-6 max-w-7xl mx-auto pb-12">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold font-serif text-gray-900 tracking-tight">Coupons</h1>
          <p className="text-sm text-muted-foreground mt-1">Create and manage discount codes</p>
        </div>
        <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
          <DialogTrigger>
            <Button className="bg-emerald-600 hover:bg-emerald-700 text-white">
              <Plus className="h-4 w-4 mr-2" />
              Create Coupon
            </Button>
          </DialogTrigger>
          <DialogContent className="max-w-lg">
            <DialogHeader>
              <DialogTitle>Create New Coupon</DialogTitle>
            </DialogHeader>
            <div className="space-y-4 mt-2">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Coupon Code *</Label>
                  <Input
                    placeholder="e.g. SAVE20"
                    value={code}
                    onChange={(e) => setCode(e.target.value.toUpperCase())}
                    className="uppercase font-mono"
                  />
                </div>
                <div className="space-y-2">
                  <Label>Discount Type *</Label>
                  <Select value={type} onValueChange={(v) => { if (v) setType(v as "percentage" | "fixed"); }}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="percentage">Percentage (%)</SelectItem>
                      <SelectItem value="fixed">Fixed (₹)</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Discount Value *</Label>
                  <Input
                    type="number"
                    placeholder={type === "percentage" ? "e.g. 20" : "e.g. 100"}
                    value={value}
                    onChange={(e) => setValue(e.target.value)}
                  />
                </div>
                <div className="space-y-2">
                  <Label>Min Order Amount</Label>
                  <Input
                    type="number"
                    placeholder="e.g. 500"
                    value={minOrder}
                    onChange={(e) => setMinOrder(e.target.value)}
                  />
                </div>
              </div>

              {type === "percentage" && (
                <div className="space-y-2">
                  <Label>Max Discount (₹)</Label>
                  <Input
                    type="number"
                    placeholder="e.g. 200"
                    value={maxDiscount}
                    onChange={(e) => setMaxDiscount(e.target.value)}
                  />
                </div>
              )}

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Valid From</Label>
                  <Input
                    type="date"
                    value={validFrom}
                    onChange={(e) => setValidFrom(e.target.value)}
                  />
                </div>
                <div className="space-y-2">
                  <Label>Valid To</Label>
                  <Input
                    type="date"
                    value={validTo}
                    onChange={(e) => setValidTo(e.target.value)}
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Total Usage Limit</Label>
                  <Input
                    type="number"
                    placeholder="Unlimited"
                    value={usageLimit}
                    onChange={(e) => setUsageLimit(e.target.value)}
                  />
                </div>
                <div className="space-y-2">
                  <Label>Per User Limit</Label>
                  <Input
                    type="number"
                    value={perUserLimit}
                    onChange={(e) => setPerUserLimit(e.target.value)}
                  />
                </div>
              </div>

              <Button
                className="w-full bg-emerald-600 hover:bg-emerald-700"
                onClick={handleCreate}
                disabled={saving}
              >
                {saving ? "Creating..." : "Create Coupon"}
              </Button>
            </div>
          </DialogContent>
        </Dialog>
      </div>

      {isLoading ? (
        <LoadingSpinner text="Loading coupons..." className="h-64" />
      ) : coupons.length === 0 ? (
        <EmptyState
          icon={Ticket}
          title="No coupons yet"
          description="Create your first discount coupon to get started."
        />
      ) : (
        <div className="grid gap-4 grid-cols-1 md:grid-cols-2 lg:grid-cols-3">
          {coupons.map((coupon) => {
            const expired = isExpired(coupon);
            const exhausted = isExhausted(coupon);
            const inactive = !coupon.is_active || expired || exhausted;

            return (
              <Card
                key={coupon.id}
                className={`shadow-sm transition-colors ${inactive ? "opacity-60 border-gray-200" : "border-emerald-100/50"}`}
              >
                <CardHeader className="pb-3 flex flex-row items-start justify-between">
                  <div className="flex items-center gap-2">
                    <div className={`flex h-9 w-9 items-center justify-center rounded-lg ${coupon.type === "percentage" ? "bg-purple-50" : "bg-emerald-50"}`}>
                      {coupon.type === "percentage" ? (
                        <Percent className="h-4 w-4 text-purple-600" />
                      ) : (
                        <DollarSign className="h-4 w-4 text-emerald-600" />
                      )}
                    </div>
                    <div>
                      <p className="font-bold font-mono text-gray-900 text-lg tracking-wide">{coupon.code}</p>
                      <p className="text-xs text-muted-foreground">
                        {coupon.type === "percentage"
                          ? `${coupon.value}% off`
                          : `${formatCurrency(coupon.value)} off`}
                        {coupon.max_discount && ` (max ${formatCurrency(coupon.max_discount)})`}
                      </p>
                    </div>
                  </div>
                  {inactive ? (
                    <Badge variant="outline" className="bg-gray-100 text-gray-600 border-gray-200 text-[10px] px-2 py-0.5 rounded-full">
                      <XCircle className="h-3 w-3 mr-1" />
                      {expired ? "Expired" : exhausted ? "Exhausted" : "Inactive"}
                    </Badge>
                  ) : (
                    <Badge variant="outline" className="bg-emerald-100 text-emerald-700 border-emerald-200 text-[10px] px-2 py-0.5 rounded-full">
                      <CheckCircle2 className="h-3 w-3 mr-1" />Active
                    </Badge>
                  )}
                </CardHeader>
                <CardContent className="pt-0">
                  <div className="space-y-2 text-xs text-gray-600">
                    {coupon.min_order_amount && (
                      <div className="flex items-center gap-2">
                        <Tag className="h-3 w-3 text-gray-400" />
                        <span>Min order: {formatCurrency(coupon.min_order_amount)}</span>
                      </div>
                    )}
                    <div className="flex items-center gap-2">
                      <Users className="h-3 w-3 text-gray-400" />
                      <span>
                        Used {coupon.used_count}{coupon.usage_limit ? ` / ${coupon.usage_limit}` : ""} times
                        {" · "}{coupon.per_user_limit}/user
                      </span>
                    </div>
                    {(coupon.valid_from || coupon.valid_to) && (
                      <div className="flex items-center gap-2">
                        <Calendar className="h-3 w-3 text-gray-400" />
                        <span>
                          {coupon.valid_from
                            ? new Date(coupon.valid_from).toLocaleDateString("en-IN", { day: "2-digit", month: "short" })
                            : "–"}{" "}
                          →{" "}
                          {coupon.valid_to
                            ? new Date(coupon.valid_to).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" })
                            : "∞"}
                        </span>
                      </div>
                    )}
                  </div>
                </CardContent>
              </Card>
            );
          })}
        </div>
      )}
    </div>
  );
}

