}

"use client";

import { useEffect, useState, useCallback } from "react";
import { BarChart3, TrendingUp, DollarSign, ArrowUp, ArrowDown, Loader2, ShoppingBag, CreditCard, Banknote } from "lucide-react";
import { Card, CardContent } from "@/components/ui/card";
import { formatCurrency } from "@/lib/utils";

interface RevenueStats {
  total_revenue: number;
  total_commission: number;
  total_delivery_fees: number;
  total_refunds: number;
  net_profit: number;
  total_orders: number;
  upi_revenue: number;
  cod_revenue: number;
}

interface DailyRevenue {
  date: string;
  revenue: number;
  orders: number;
}

export default function AdminRevenuePage() {
  const [stats, setStats] = useState<RevenueStats>({
    total_revenue: 0, total_commission: 0, total_delivery_fees: 0,
    total_refunds: 0, net_profit: 0, total_orders: 0, upi_revenue: 0, cod_revenue: 0,
  });
  const [dailyData, setDailyData] = useState<DailyRevenue[]>([]);
  const [loading, setLoading] = useState(true);
  const [period, setPeriod] = useState<"7d" | "30d" | "90d">("30d");

  const fetchData = useCallback(async () => {
    setLoading(true);
    try {
      const res = await fetch(`/api/admin/finance/revenue?period=${period}`);
      const json = await res.json();
      if (res.ok) {
        setStats(json.stats || stats);
        setDailyData(json.daily || []);
      }
    } catch { /* empty */ }
    finally { setLoading(false); }
  }, [period]);

  useEffect(() => { fetchData(); }, [fetchData]);

  const maxRevenue = Math.max(...dailyData.map((d) => d.revenue), 1);

  const statCards = [
    { label: "Total Revenue", value: stats.total_revenue, icon: TrendingUp, color: "text-emerald-600 bg-emerald-50" },
    { label: "Commission Earned", value: stats.total_commission, icon: DollarSign, color: "text-blue-600 bg-blue-50" },
    { label: "Delivery Fees", value: stats.total_delivery_fees, icon: ShoppingBag, color: "text-purple-600 bg-purple-50" },
    { label: "Refunds", value: stats.total_refunds, icon: ArrowDown, color: "text-red-600 bg-red-50" },
    { label: "Net Profit", value: stats.net_profit, icon: ArrowUp, color: "text-emerald-700 bg-emerald-100" },
    { label: "Total Orders", value: stats.total_orders, icon: BarChart3, color: "text-gray-600 bg-gray-50", isCurrency: false },
  ];

  return (
    <div className="space-y-6 max-w-7xl mx-auto pb-12">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold font-serif text-gray-900 tracking-tight">Revenue</h1>
          <p className="text-sm text-muted-foreground mt-1">Platform revenue analytics and breakdown</p>
        </div>
        <div className="flex gap-1 bg-gray-100 rounded-lg p-1">
          {(["7d", "30d", "90d"] as const).map((p) => (
            <button key={p} onClick={() => setPeriod(p)} className={`px-3 py-1.5 rounded-md text-xs font-medium transition-all ${period === p ? "bg-white text-gray-900 shadow-sm" : "text-gray-500 hover:text-gray-700"}`}>
              {p === "7d" ? "7 Days" : p === "30d" ? "30 Days" : "90 Days"}
            </button>
          ))}
        </div>
      </div>

      {loading ? (
        <div className="flex justify-center py-20"><Loader2 className="h-8 w-8 animate-spin text-emerald-500" /></div>
      ) : (
        <>
          {/* Stat Cards */}
          <div className="grid gap-4 grid-cols-2 lg:grid-cols-3">
            {statCards.map((card) => {
              const Icon = card.icon;
              return (
                <Card key={card.label} className="shadow-sm">
                  <CardContent className="p-4">
                    <div className="flex items-center gap-3">
                      <div className={`h-10 w-10 rounded-lg ${card.color} flex items-center justify-center`}>
                        <Icon className="h-5 w-5" />
                      </div>
                      <div>
                        <p className="text-2xl font-bold text-gray-900">
                          {card.isCurrency === false ? card.value : formatCurrency(card.value)}
                        </p>
                        <p className="text-xs text-muted-foreground">{card.label}</p>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              );
            })}
          </div>

          {/* Payment Split */}
          <div className="grid gap-4 grid-cols-2">
            <Card className="shadow-sm">
              <CardContent className="p-5 flex items-center gap-4">
                <div className="h-12 w-12 rounded-xl bg-blue-50 flex items-center justify-center">
                  <CreditCard className="h-6 w-6 text-blue-600" />
                </div>
                <div>
                  <p className="text-xl font-bold text-gray-900">{formatCurrency(stats.upi_revenue)}</p>
                  <p className="text-xs text-muted-foreground">UPI / Online</p>
                </div>
              </CardContent>
            </Card>
            <Card className="shadow-sm">
              <CardContent className="p-5 flex items-center gap-4">
                <div className="h-12 w-12 rounded-xl bg-amber-50 flex items-center justify-center">
                  <Banknote className="h-6 w-6 text-amber-600" />
                </div>
                <div>
                  <p className="text-xl font-bold text-gray-900">{formatCurrency(stats.cod_revenue)}</p>
                  <p className="text-xs text-muted-foreground">Cash on Delivery</p>
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Daily Revenue Chart (simple bar chart) */}
          {dailyData.length > 0 && (
            <Card className="shadow-sm">
              <CardContent className="p-5">
                <h3 className="font-semibold text-gray-900 mb-4">Daily Revenue</h3>
                <div className="flex items-end gap-1 h-40">
                  {dailyData.map((d) => (
                    <div key={d.date} className="flex-1 flex flex-col items-center gap-1 group relative" title={`${new Date(d.date).toLocaleDateString("en-IN", { day: "2-digit", month: "short" })}: ${formatCurrency(d.revenue)} (${d.orders} orders)`}>
                      <div className="w-full rounded-t-sm bg-emerald-400 transition-all group-hover:bg-emerald-500" style={{ height: `${(d.revenue / maxRevenue) * 100}%`, minHeight: d.revenue > 0 ? "4px" : "0px" }} />
                    </div>
                  ))}
                </div>
                <div className="flex justify-between mt-2 text-[9px] text-muted-foreground">
                  <span>{dailyData[0]?.date ? new Date(dailyData[0].date).toLocaleDateString("en-IN", { day: "2-digit", month: "short" }) : ""}</span>
                  <span>{dailyData[dailyData.length - 1]?.date ? new Date(dailyData[dailyData.length - 1].date).toLocaleDateString("en-IN", { day: "2-digit", month: "short" }) : ""}</span>
                </div>
              </CardContent>
            </Card>
          )}
        </>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import {
  Leaf, Calendar, Eye, CheckCircle2, Clock, Phone, MapPin,
  Loader2, FileText, ChevronDown, Send,
} from "lucide-react";
import { toast } from "sonner";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { formatDate, formatStatus, getStatusColor } from "@/lib/helpers/format";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";

interface Booking {
  id: string;
  booking_number: string;
  customer_name: string;
  customer_phone: string;
  customer_email: string | null;
  service_type: string;
  address: string;
  area_size: string | null;
  preferred_date: string | null;
  description: string | null;
  budget_range: string | null;
  status: string;
  admin_notes: string | null;
  quoted_price: number | null;
  final_price: number | null;
  scheduled_visit_date: string | null;
  created_at: string;
}

const STATUS_FLOW = ["inquiry", "site_visit_scheduled", "site_visit_done", "quote_sent", "accepted", "in_progress", "completed", "cancelled"];

const STATUS_ACTIONS: Record<string, { next: string; label: string }> = {
  inquiry: { next: "site_visit_scheduled", label: "Schedule Visit" },
  site_visit_scheduled: { next: "site_visit_done", label: "Mark Visited" },
  site_visit_done: { next: "quote_sent", label: "Send Quote" },
  quote_sent: { next: "accepted", label: "Mark Accepted" },
  accepted: { next: "in_progress", label: "Start Work" },
  in_progress: { next: "completed", label: "Mark Completed" },
};

export default function AdminLandscapePage() {
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState("all");
  const [selectedBooking, setSelectedBooking] = useState<Booking | null>(null);
  const [detailOpen, setDetailOpen] = useState(false);
  const [actionLoading, setActionLoading] = useState(false);

  // Form fields for status actions
  const [visitDate, setVisitDate] = useState("");
  const [quotedPrice, setQuotedPrice] = useState("");
  const [adminNotes, setAdminNotes] = useState("");

  useEffect(() => { fetchBookings(); }, [activeTab]);

  const fetchBookings = async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      if (activeTab !== "all") params.set("status", activeTab);
      const res = await fetch(`/api/Landscape/bookings?${params}`);
      const json = await res.json();
      if (res.ok) setBookings(json.data || []);
    } catch { /* empty */ }
    finally { setLoading(false); }
  };

  const handleStatusUpdate = async (bookingId: string, newStatus: string, extraData: Record<string, unknown> = {}) => {
    setActionLoading(true);
    try {
      const res = await fetch(`/api/Landscape/bookings/${bookingId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ status: newStatus, admin_notes: adminNotes, ...extraData }),
      });
      if (!res.ok) throw new Error("Update failed");
      toast.success(`Status updated to ${formatStatus(newStatus)}`);
      fetchBookings();
      setDetailOpen(false);
    } catch {
      toast.error("Failed to update");
    } finally { setActionLoading(false); }
  };

  const openDetail = (booking: Booking) => {
    setSelectedBooking(booking);
    setAdminNotes(booking.admin_notes || "");
    setVisitDate(booking.scheduled_visit_date || "");
    setQuotedPrice(booking.quoted_price?.toString() || "");
    setDetailOpen(true);
  };

  const tabs = ["all", "inquiry", "site_visit_scheduled", "site_visit_done", "quote_sent", "accepted", "in_progress", "completed"];

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="font-heading text-2xl font-bold text-on-surface">Landscape Landscape</h1>
          <p className="text-sm text-on-surface-variant mt-1">Manage consultation requests and projects</p>
        </div>
        <div className="flex items-center gap-2">
          <Leaf className="h-5 w-5 text-botanical" />
          <span className="text-sm font-medium text-on-surface">{bookings.length} bookings</span>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex gap-2 overflow-x-auto scrollbar-hide pb-1">
        {tabs.map((tab) => (
          <button key={tab} onClick={() => setActiveTab(tab)} className={`px-3 py-1.5 rounded-full text-xs font-medium transition-all shrink-0 ${activeTab === tab ? "bg-botanical-gradient text-white" : "bg-surface-low text-on-surface-variant hover:bg-surface-high"}`}>
            {tab === "all" ? "All" : formatStatus(tab)}
          </button>
        ))}
      </div>

      {/* List */}
      {loading ? (
        <div className="flex justify-center py-20"><Loader2 className="h-8 w-8 animate-spin text-botanical" /></div>
      ) : bookings.length === 0 ? (
        <div className="text-center py-20">
          <Leaf className="h-12 w-12 mx-auto text-on-surface-variant/30 mb-3" />
          <p className="text-on-surface-variant">No bookings found</p>
        </div>
      ) : (
        <div className="space-y-3">
          {bookings.map((b) => (
            <div key={b.id} onClick={() => openDetail(b)} className="bg-surface-lowest rounded-2xl shadow-ambient-sm p-4 sm:p-5 hover:shadow-ambient transition-shadow cursor-pointer group">
              <div className="flex items-start justify-between gap-3">
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-1">
                    <span className="font-mono text-sm font-semibold text-on-surface">{b.booking_number}</span>
                    <span className={`px-2 py-0.5 rounded-full text-[10px] font-semibold uppercase tracking-wider ${getStatusColor(b.status)}`}>
                      {formatStatus(b.status)}
                    </span>
                  </div>
                  <p className="text-sm font-medium text-on-surface">{b.customer_name}</p>
                  <div className="flex items-center gap-3 mt-1 text-xs text-on-surface-variant">
                    <span className="flex items-center gap-1"><Phone className="h-3 w-3" />{b.customer_phone}</span>
                    <span className="capitalize">{b.service_type.replace(/-/g, " ")}</span>
                  </div>
                </div>
                <div className="text-right shrink-0">
                  <p className="text-xs text-on-surface-variant">{formatDate(b.created_at)}</p>
                  {b.quoted_price && <p className="text-sm font-semibold text-botanical mt-1">₹{b.quoted_price.toLocaleString("en-IN")}</p>}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Detail Dialog */}
      <Dialog open={detailOpen} onOpenChange={setDetailOpen}>
        <DialogContent className="max-w-lg bg-surface-lowest max-h-[85vh] overflow-y-auto">
          <DialogHeader><DialogTitle className="font-heading">Booking Details</DialogTitle></DialogHeader>
          {selectedBooking && (
            <div className="space-y-4 mt-2">
              <div className="flex justify-between items-start">
                <div>
                  <p className="font-mono text-sm font-semibold">{selectedBooking.booking_number}</p>
                  <p className="text-sm font-medium text-on-surface mt-1">{selectedBooking.customer_name}</p>
                </div>
                <span className={`px-2.5 py-0.5 rounded-full text-[10px] font-semibold uppercase ${getStatusColor(selectedBooking.status)}`}>
                  {formatStatus(selectedBooking.status)}
                </span>
              </div>

              <div className="grid grid-cols-2 gap-3 text-sm">
                <div><span className="text-xs text-on-surface-variant">Phone</span><p className="font-medium">{selectedBooking.customer_phone}</p></div>
                {selectedBooking.customer_email && <div><span className="text-xs text-on-surface-variant">Email</span><p className="font-medium">{selectedBooking.customer_email}</p></div>}
                <div><span className="text-xs text-on-surface-variant">Service</span><p className="font-medium capitalize">{selectedBooking.service_type.replace(/-/g, " ")}</p></div>
                {selectedBooking.area_size && <div><span className="text-xs text-on-surface-variant">Area</span><p className="font-medium">{selectedBooking.area_size}</p></div>}
                {selectedBooking.budget_range && <div><span className="text-xs text-on-surface-variant">Budget</span><p className="font-medium">{selectedBooking.budget_range}</p></div>}
                {selectedBooking.preferred_date && <div><span className="text-xs text-on-surface-variant">Preferred Date</span><p className="font-medium">{selectedBooking.preferred_date}</p></div>}
              </div>

              <div>
                <span className="text-xs text-on-surface-variant">Address</span>
                <p className="text-sm">{selectedBooking.address}</p>
              </div>

              {selectedBooking.description && (
                <div>
                  <span className="text-xs text-on-surface-variant">Requirements</span>
                  <p className="text-sm">{selectedBooking.description}</p>
                </div>
              )}

              <div className="h-px bg-surface-high" />

              {/* Admin notes */}
              <div>
                <span className="text-xs text-on-surface-variant">Admin Notes</span>
                <Textarea value={adminNotes} onChange={(e) => setAdminNotes(e.target.value)} className="bg-surface-high border-0 mt-1 min-h-[60px] text-sm" placeholder="Internal notes..." />
              </div>

              {/* Schedule visit date */}
              {selectedBooking.status === "inquiry" && (
                <div>
                  <span className="text-xs text-on-surface-variant">Schedule Visit Date</span>
                  <Input type="date" value={visitDate} onChange={(e) => setVisitDate(e.target.value)} className="bg-surface-high border-0 mt-1" />
                </div>
              )}

              {/* Quote price */}
              {selectedBooking.status === "site_visit_done" && (
                <div>
                  <span className="text-xs text-on-surface-variant">Quoted Price (₹)</span>
                  <Input type="number" value={quotedPrice} onChange={(e) => setQuotedPrice(e.target.value)} className="bg-surface-high border-0 mt-1" placeholder="25000" />
                </div>
              )}

              {/* Action buttons */}
              <div className="flex gap-2">
                {STATUS_ACTIONS[selectedBooking.status] && (
                  <button
                    onClick={() => {
                      const extra: Record<string, unknown> = {};
                      if (selectedBooking.status === "inquiry") extra.scheduled_visit_date = visitDate;
                      if (selectedBooking.status === "site_visit_done") extra.quoted_price = Number(quotedPrice);
                      handleStatusUpdate(selectedBooking.id, STATUS_ACTIONS[selectedBooking.status].next, extra);
                    }}
                    disabled={actionLoading}
                    className="flex-1 h-10 rounded-full bg-botanical-gradient text-white text-sm font-medium flex items-center justify-center gap-2 disabled:opacity-40"
                  >
                    {actionLoading ? <Loader2 className="h-4 w-4 animate-spin" /> : <CheckCircle2 className="h-4 w-4" />}
                    {STATUS_ACTIONS[selectedBooking.status].label}
                  </button>
                )}
                {selectedBooking.status !== "completed" && selectedBooking.status !== "cancelled" && (
                  <button onClick={() => handleStatusUpdate(selectedBooking.id, "cancelled")} disabled={actionLoading} className="px-4 h-10 rounded-full border border-red-200 text-red-600 text-sm font-medium hover:bg-red-50 disabled:opacity-40">
                    Cancel
                  </button>
                )}
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

