      {isLoading ? (
        <LoadingSpinner text="Loading orders..." className="h-64" />
      ) : filtered.length === 0 ? (
        <EmptyState
          icon={ShoppingBag}
          title="No orders found"
          description={statusFilter !== "all" ? "Try changing the status filter." : "No orders have been placed yet."}
