import { NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";

/**
 * GET /api/admin/customers
 * Returns all buyer accounts with order counts
 */
export async function GET(request: Request) {
  try {
    const supabase = await createClient();

    const { data: { user } } = await supabase.auth.getUser();
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const { data: userData } = await supabase
      .from("users")
      .select("role")
      .eq("id", user.id)
      .single();

    if (userData?.role !== "admin") {
      return NextResponse.json({ error: "Forbidden" }, { status: 403 });
    }

    const { searchParams } = new URL(request.url);
    const page = parseInt(searchParams.get("page") || "1", 10);
    const perPage = 20;
    const offset = (page - 1) * perPage;

    const { data: customers, error, count } = await supabase
      .from("users")
      .select("id, full_name, email, phone, role, is_active, avatar_url, created_at", { count: "exact" })
      .eq("role", "buyer")
      .order("created_at", { ascending: false })
      .range(offset, offset + perPage - 1);

    if (error) {
      console.error("Admin customers error:", error);
      return NextResponse.json({ error: "Database error" }, { status: 500 });
    }

    // Get order counts per customer
    const customerIds = (customers || []).map((c) => c.id);
    let orderCounts: Record<string, number> = {};

    if (customerIds.length > 0) {
      const { data: orderData } = await supabase
        .from("orders")
        .select("user_id")
        .in("user_id", customerIds);

      if (orderData) {
        for (const o of orderData) {
          orderCounts[o.user_id] = (orderCounts[o.user_id] || 0) + 1;
        }
      }
    }

    const formattedCustomers = (customers || []).map((c) => ({
      id: c.id,
      full_name: c.full_name,
      email: c.email,
      phone: c.phone,
      is_active: c.is_active,
      avatar_url: c.avatar_url,
      order_count: orderCounts[c.id] || 0,
      date: c.created_at,
    }));

    return NextResponse.json({
      customers: formattedCustomers,
      total: count || 0,
      page,
      perPage,
    });
  } catch (err) {
    console.error("Admin Customers API Error:", err);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";
import { createClient } from "@/lib/supabase/server";

/**
 * GET /api/admin/finance/revenue — Revenue analytics
 */
export async function GET(request: NextRequest) {
  try {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

    const { data: userData } = await supabase.from("users").select("role").eq("id", user.id).single();
    if (userData?.role !== "admin") return NextResponse.json({ error: "Admin only" }, { status: 403 });

    const { searchParams } = new URL(request.url);
    const period = searchParams.get("period") || "30d";

    const days = period === "7d" ? 7 : period === "90d" ? 90 : 30;
    const startDate = new Date();
    startDate.setDate(startDate.getDate() - days);

    // Get orders in period
    const { data: orders } = await supabase
      .from("orders")
      .select("total, subtotal, delivery_fee, discount, payment_method, payment_status, status, created_at")
      .gte("created_at", startDate.toISOString())
      .neq("status", "cancelled");

    const allOrders = orders || [];
    const delivered = allOrders.filter((o) => o.status === "delivered");

    // Calculate stats
    const total_revenue = allOrders.reduce((s, o) => s + (o.total || 0), 0);
    const total_delivery_fees = allOrders.reduce((s, o) => s + (o.delivery_fee || 0), 0);
    const total_refunds = 0; // TODO: sum from refunds table
    const upi_revenue = allOrders.filter((o) => o.payment_method === "upi").reduce((s, o) => s + (o.total || 0), 0);
    const cod_revenue = allOrders.filter((o) => o.payment_method === "cod").reduce((s, o) => s + (o.total || 0), 0);

    // Commission from order_sellers
    const { data: subOrders } = await supabase
      .from("order_sellers")
      .select("commission_amount, orders!inner(created_at, status)")
      .gte("orders.created_at", startDate.toISOString());

    const total_commission = (subOrders || []).reduce((s, so) => s + (so.commission_amount || 0), 0);
    const net_profit = total_commission + total_delivery_fees - total_refunds;

    // Daily revenue
    const dailyMap: Record<string, { revenue: number; orders: number }> = {};
    for (let i = 0; i < days; i++) {
      const d = new Date();
      d.setDate(d.getDate() - (days - 1 - i));
      const key = d.toISOString().split("T")[0];
      dailyMap[key] = { revenue: 0, orders: 0 };
    }

    allOrders.forEach((o) => {
      const key = o.created_at.split("T")[0];
      if (dailyMap[key]) {
        dailyMap[key].revenue += o.total || 0;
        dailyMap[key].orders += 1;
      }
    });

    const daily = Object.entries(dailyMap).map(([date, data]) => ({
      date,
      revenue: data.revenue,
      orders: data.orders,
    }));

    return NextResponse.json({
      stats: {
        total_revenue,
        total_commission,
        total_delivery_fees,
        total_refunds,
        net_profit,
        total_orders: allOrders.length,
        upi_revenue,
        cod_revenue,
      },
      daily,
    });
  } catch (error) {
    console.error("Revenue API error:", error);
    return NextResponse.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";

/**
 * GET /api/admin/riders — All riders
 */
export async function GET() {
  try {
    const supabase = await createClient();

    const { data: { user } } = await supabase.auth.getUser();
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const { data: userData } = await supabase
      .from("users")
      .select("role")
      .eq("id", user.id)
      .single();

    if (userData?.role !== "admin") {
      return NextResponse.json({ error: "Forbidden" }, { status: 403 });
    }

    const { data: riders, error } = await supabase
      .from("riders")
      .select("id, user_id, name, phone, vehicle_type, vehicle_number, is_available, is_active, total_deliveries, created_at")
      .order("created_at", { ascending: false });

    if (error) {
      console.error("Admin riders error:", error);
      return NextResponse.json({ error: "Database error" }, { status: 500 });
    }

    // Get pending COD for each rider
    const riderIds = (riders || []).map((r) => r.id);
    let codPending: Record<string, number> = {};

    if (riderIds.length > 0) {
      const { data: codData } = await supabase
        .from("cod_collections")
        .select("rider_id, amount")
        .in("rider_id", riderIds)
        .eq("status", "collected");

      if (codData) {
        for (const c of codData) {
          codPending[c.rider_id] = (codPending[c.rider_id] || 0) + Number(c.amount);
        }
      }
    }

    const formatted = (riders || []).map((r) => ({
      ...r,
      cod_pending: codPending[r.id] || 0,
    }));

    return NextResponse.json({ riders: formatted });
  } catch (err) {
    console.error("Admin Riders API Error:", err);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

