    const { id: storeId } = await params;

    const { data: { user } } = await supabase.auth.getUser();
    if (!user || user.user_metadata?.role !== "admin") {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    // 1. Fetch Store Profile
    const { data: store } = await supabase
      .from("stores")
      .select("*")
      .eq("id", storeId)
      .single();

    if (!store) {
      return NextResponse.json({ error: "Store not found" }, { status: 404 });
    }

    // 2. Fetch Bank Details
    const { data: bankResult } = await supabase
      .from("seller_bank_details")
      .select("*")
      .eq("store_id", storeId)
      .single();

    // 3. Fetch Documents
    const { data: docs } = await supabase
      .from("seller_documents")
      .select("*")
      .eq("store_id", storeId);

    // 4. Generate Signed URLs for documents since the bucket is private
    const documentsWithUrls = await Promise.all((docs || []).map(async (doc: any) => {
      let viewUrl = doc.document_url;
      // If it's not an external HTTP link, assume it's a storage path
      if (viewUrl && !viewUrl.startsWith("http")) {
        const { data: signedData } = await supabase.storage
          .from("seller-documents")
          .createSignedUrl(viewUrl, 60 * 60); // 1 hour expiry

        if (signedData?.signedUrl) {
          viewUrl = signedData.signedUrl;
        }
      }

      return {
        ...doc,
        view_url: viewUrl,
      };
    }));

    return NextResponse.json({
      store,
      bankDetails: bankResult || null,
      documents: documentsWithUrls
    });

  } catch (error: any) {
    console.error("Admin Sellers Detail GET Error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

export async function PUT(request: Request, { params }: { params: Promise<{ id: string }> }) {
  try {
    const supabase = await createClient();
    const { id: storeId } = await params;

    const { data: { user } } = await supabase.auth.getUser();
    if (!user || user.user_metadata?.role !== "admin") {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    let payload;
    try {
      payload = await request.json();
    } catch {
      return NextResponse.json({ error: "Invalid JSON payload" }, { status: 400 });
    }

    const { status, approval_note } = payload;

    if (!status || !["active", "rejected", "suspended"].includes(status)) {
      return NextResponse.json({ error: "Invalid status" }, { status: 400 });
    }

    const { error: updateError } = await supabase
      .from("stores")
      .update({
        status,
        approval_note: approval_note || null,
        approved_at: status === "active" ? new Date().toISOString() : null,
        approved_by: status === "active" ? user.id : null,
        is_active: status === "active"
      })
      .eq("id", storeId);

    if (updateError) {
      return NextResponse.json({ error: updateError.message }, { status: 500 });
    }

    return NextResponse.json({ success: true, status });

  } catch (error: any) {
    console.error("Admin Sellers Detail PUT Error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

