import { createClient } from "@/lib/supabase/server";

/**
 * GET /api/categories — List all categories with children count
 * POST /api/categories — Create a new category (admin only)
 */
export async function GET() {
  try {
    const supabase = await createClient();

    const { data, error } = await supabase
      .from("categories")
      .select("*, children:categories!parent_id(id)")
      .is("parent_id", null)
      .order("sort_order", { ascending: true });

    if (error) {
      return NextResponse.json({ error: error.message }, { status: 500 });
    }

    // Also fetch subcategories for each parent
    const { data: allCategories, error: allError } = await supabase
      .from("categories")
      .select("*")
      .order("sort_order", { ascending: true });

    if (allError) {
      return NextResponse.json({ error: allError.message }, { status: 500 });
    }

    // Build tree structure
    const tree = allCategories
      .filter((c) => c.parent_id === null)
      .map((parent) => ({
        ...parent,
        children: allCategories.filter((c) => c.parent_id === parent.id),
      }));

    return NextResponse.json({ data: tree }, { status: 200 });
  } catch (error) {
    console.error("Categories GET error:", error);
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 }
    );
  }
}

export async function POST(request: NextRequest) {
  try {
    const supabase = await createClient();

    // Check admin role
    const {
      data: { user },
    } = await supabase.auth.getUser();
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const { data: profile } = await supabase
      .from("users")
      .select("role")
      .eq("id", user.id)
      .single();

    if (profile?.role !== "admin") {
      return NextResponse.json({ error: "Admin access required" }, { status: 403 });
    }

    const body = await request.json();
    const { name, slug, description, image_url, parent_id, sort_order, is_active } = body;

    if (!name || !slug) {
      return NextResponse.json(
        { error: "Name and slug are required" },
        { status: 400 }
      );
    }

    // Check for duplicate slug
    const { data: existing } = await supabase
      .from("categories")
      .select("id")
      .eq("slug", slug)
      .single();

    if (existing) {
      return NextResponse.json(
        { error: "A category with this slug already exists" },
        { status: 409 }
      );
    }

    const { data: newCategory, error } = await supabase
      .from("categories")
      .insert({
        name,
        slug,
        description: description || null,
        image_url: image_url || null,
        parent_id: parent_id || null,
        sort_order: sort_order ?? 0,
        is_active: is_active ?? true,
      })
      .select()
      .single();

    if (error) {
      console.error("Category create error:", error);
      return NextResponse.json(
        { error: "Failed to create category" },
        { status: 500 }
      );
    }

    return NextResponse.json({ data: newCategory }, { status: 201 });
  } catch (error) {
    console.error("Categories POST error:", error);
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";
import { createClient } from "@/lib/supabase/server";
import { generateOrderNumber } from "@/lib/helpers/order";
import { generateOTP, hashOTP } from "@/lib/helpers/otp";
import { calculateCommission } from "@/lib/helpers/commission";
import { verifyPaymentSignature } from "@/lib/razorpay/utils";

type CartLineItem = {
  product_id: string;
  variant_id: string | null;
  quantity: number;
  price: number;
  store_id: string;
  name?: string;
  image?: string | null;
  variant_name?: string | null;
};

/**
 * POST /api/orders — Place a new multi-seller order
 * Supports UPI (Razorpay) and COD payment methods.
 * Splits cart into sub-orders per seller, snapshots commission, deducts stock.
 */
export async function POST(request: NextRequest) {
  try {
    const supabase = await createClient();
    const {
      data: { user },
    } = await supabase.auth.getUser();
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const body = await request.json();
    const {
      items,
      address,
      payment_method,
      delivery_slot,
      delivery_date,
      note,
      gift_message,
      subtotal,
      delivery_fee,
      discount,
      total,
      coupon_code,
      coupon_id,
      // Razorpay fields (for UPI)
      razorpay_order_id,
      razorpay_payment_id,
      razorpay_signature,
    } = body;

    if (!items?.length || !address || !payment_method) {
      return NextResponse.json(
        { error: "Missing required fields" },
        { status: 400 }
      );
    }

    // Validate payment method
    if (!["upi", "cod"].includes(payment_method)) {
      return NextResponse.json(
        { error: "Invalid payment method" },
        { status: 400 }
      );
    }

    // For UPI payments, verify the Razorpay signature
    let paymentStatus = "pending";
    if (payment_method === "upi") {
      if (!razorpay_order_id || !razorpay_payment_id || !razorpay_signature) {
        return NextResponse.json(
          { error: "Missing payment verification data for UPI" },
          { status: 400 }
        );
      }

      const isValid = verifyPaymentSignature({
        razorpay_order_id,
        razorpay_payment_id,
        razorpay_signature,
      });

      if (!isValid) {
        return NextResponse.json(
          { error: "Payment verification failed" },
          { status: 400 }
        );
      }

      paymentStatus = "paid";
    }

    // Build delivery address JSONB
    const deliveryAddress = {
      full_name: address.full_name,
      phone: address.phone,
      full_address: address.full_address || address.address_line1 || "",
      address_line2: address.address_line2 || "",
      landmark: address.landmark || "",
      pin_code: address.pin_code || address.pincode || "",
      city: address.city || "Daltonganj",
      state: address.state || "Jharkhand",
      label: address.label || "Home",
    };

    // Generate order number + delivery OTP
    const orderNumber = generateOrderNumber();
    const rawOtp = generateOTP();
    const hashedOtp = hashOTP(rawOtp);

    // Create main order
    const { data: order, error: orderErr } = await supabase
      .from("orders")
      .insert({
        user_id: user.id,
        order_number: orderNumber,
        status: "placed",
        subtotal: subtotal || 0,
        delivery_fee: delivery_fee || 0,
        discount: discount || 0,
        total: total || 0,
        payment_method,
        payment_status: paymentStatus,
        razorpay_order_id: razorpay_order_id || null,
        razorpay_payment_id: razorpay_payment_id || null,
        delivery_address: deliveryAddress,
        delivery_otp: hashedOtp,
        delivery_date: delivery_date || new Date().toISOString().split("T")[0],
        coupon_id: coupon_id || null,
        coupon_code: coupon_code || null,
        gift_message: gift_message || null,
        special_instructions: note || null,
      })
      .select("id, order_number")
      .single();

    if (orderErr) {
      console.error("Order creation error:", orderErr);
      return NextResponse.json(
        { error: `Failed to create order: ${orderErr.message}` },
        { status: 500 }
      );
    }

    // Group items by store
    const itemsByStore = new Map<string, CartLineItem[]>();
    for (const item of items as CartLineItem[]) {
      if (!itemsByStore.has(item.store_id)) {
        itemsByStore.set(item.store_id, []);
      }
      itemsByStore.get(item.store_id)!.push(item);
    }

    // Create sub-orders per store
    for (const [storeId, storeItems] of itemsByStore.entries()) {
      const storeSubtotal = storeItems.reduce(
        (sum, i) => sum + i.price * i.quantity,
        0
      );

      // Look up seller's custom commission rate (if any)
      const { data: store } = await supabase
        .from("stores")
        .select("commission_rate, address, store_name")
        .eq("id", storeId)
        .single();

      const commission = calculateCommission(
        storeSubtotal,
        store?.commission_rate
      );

      // Snapshot seller's pickup address
      const pickupAddress = store
        ? {
            store_name: store.store_name,
            address: store.address,
          }
        : null;

      const { data: subOrder, error: subErr } = await supabase
        .from("order_sellers")
        .insert({
          order_id: order.id,
          store_id: storeId,
          status: "placed",
          subtotal: storeSubtotal,
          commission_rate: commission.commission_rate,
          commission_amount: commission.commission_amount,
          seller_amount: commission.seller_amount,
          pickup_address: pickupAddress,
        })
        .select("id")
        .single();

      if (subErr) {
        console.error(`Sub-order error for store ${storeId}:`, subErr);
        continue;
      }

      // Create order items linked to sub-order
      const orderItems = storeItems.map((item) => ({
        order_id: order.id,
        order_seller_id: subOrder.id,
        product_id: item.product_id,
        variant_id: item.variant_id || null,
        quantity: item.quantity,
        unit_price: item.price,
        total_price: item.price * item.quantity,
        product_name: item.name || "Product",
        product_image: item.image || null,
        variant_name: item.variant_name || null,
      }));

      await supabase.from("order_items").insert(orderItems);

      // Deduct stock atomically
      for (const item of storeItems) {
        if (item.variant_id) {
          const { data: variant } = await supabase
            .from("product_variants")
            .select("stock_qty")
            .eq("id", item.variant_id)
            .single();
          if (variant) {
            await supabase
              .from("product_variants")
              .update({
                stock_qty: Math.max(0, variant.stock_qty - item.quantity),
              })
              .eq("id", item.variant_id);
          }
        } else {
          const { data: product } = await supabase
            .from("products")
            .select("stock_qty")
            .eq("id", item.product_id)
            .single();
          if (product) {
            await supabase
              .from("products")
              .update({
                stock_qty: Math.max(0, product.stock_qty - item.quantity),
              })
              .eq("id", item.product_id);
          }
        }
      }

      // Create seller notification
      await supabase.from("seller_notifications").insert({
        store_id: storeId,
        type: "order_new",
        title: "New Order Received!",
        message: `Order #${orderNumber} — ${storeItems.length} item(s) worth ₹${storeSubtotal}`,
        data: { order_id: order.id, order_seller_id: subOrder.id },
      });
    }

    // Record status history
    await supabase.from("order_status_history").insert({
      order_id: order.id,
      status: "placed",
      changed_by: user.id,
      note: `Order placed via ${payment_method.toUpperCase()}`,
    });

    // Clear buyer's cart items from DB (if stored)
    await supabase.from("cart_items").delete().eq("user_id", user.id);

    // Track coupon usage if applied
    if (coupon_id) {
      await supabase.from("coupon_usage").insert({
        coupon_id,
        user_id: user.id,
        order_id: order.id,
        discount_amount: discount || 0,
      });

      // Increment coupon used_count
      const { data: couponData } = await supabase
        .from("coupons")
        .select("used_count")
        .eq("id", coupon_id)
        .single();
      if (couponData) {
        await supabase
          .from("coupons")
          .update({ used_count: (couponData.used_count || 0) + 1 })
          .eq("id", coupon_id);
      }
    }

    return NextResponse.json(
      {
        data: {
          ...order,
          delivery_otp: rawOtp, // Return raw OTP to buyer (show on confirmation page)
        },
      },
      { status: 201 }
    );
  } catch (error) {
    console.error("Order API error:", error);
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 }
    );
  }
}

/**
 * GET /api/orders — List current user's orders
 */
export async function GET(request: NextRequest) {
  try {
    const supabase = await createClient();
    const {
      data: { user },
    } = await supabase.auth.getUser();
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const { searchParams } = new URL(request.url);
    const status = searchParams.get("status");
    const page = parseInt(searchParams.get("page") || "1", 10);
    const pageSize = parseInt(searchParams.get("pageSize") || "10", 10);

    let query = supabase
      .from("orders")
      .select(
        "*, order_sellers(*, stores(id, store_name), order_items(*))",
        { count: "exact" }
      )
      .eq("user_id", user.id)
      .order("created_at", { ascending: false });

    if (status && status !== "all") {
      query = query.eq("status", status);
    }

    query = query.range((page - 1) * pageSize, page * pageSize - 1);

    const { data, error, count } = await query;

    if (error) {
      return NextResponse.json({ error: error.message }, { status: 500 });
    }

    return NextResponse.json(
      {
        data: data || [],
        count: count || 0,
        page,
        pageSize,
      },
      { status: 200 }
    );
  } catch (error) {
    console.error("Orders GET error:", error);
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";

export async function POST(request: Request) {
  try {
    const supabase = await createClient();

    // Verify auth
    const { data: { user }, error: userError } = await supabase.auth.getUser();
    if (userError || !user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    // Get seller's store id
    const { data: store } = await supabase
      .from("stores")
      .select("id")
      .eq("user_id", user.id)
      .single();

    if (!store) {
      return NextResponse.json({ error: "Please complete previous steps first." }, { status: 400 });
    }

    const payload = await request.json();
    const {
      account_holder,
      account_number,
      ifsc_code,
      bank_name,
      upi_id,
    } = payload;

    if (!account_holder || !account_number || !ifsc_code || !bank_name) {
      return NextResponse.json({ error: "Missing required fields" }, { status: 400 });
    }

    // Delete existing if re-submitting
    await supabase.from("seller_bank_details").delete().eq("store_id", store.id);

    const { error: insertError } = await supabase
      .from("seller_bank_details")
      .insert({
        store_id: store.id,
        account_holder,
        account_number,
        ifsc_code,
        bank_name,
        upi_id,
        is_verified: false,
      });

    if (insertError) {
      console.error("Bank insert error:", insertError);
      return NextResponse.json({ error: insertError.message }, { status: 500 });
    }

    // Mark store as completely submitted for review (status = pending)
    // It's already pending from the `store` step, but we can update updated_at
    await supabase.from("stores").update({ updated_at: new Date().toISOString() }).eq("id", store.id);

    return NextResponse.json({ success: true });
  } catch (err: any) {
    console.error("Bank API Error:", err);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";

export async function GET(request: Request) {
  try {
    const supabase = await createClient();

    const { data: { user } } = await supabase.auth.getUser();
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const { data: store } = await supabase
      .from("stores")
      .select("id, rating")
      .eq("user_id", user.id)
      .single();

    if (!store) {
      return NextResponse.json({ error: "Store not found" }, { status: 404 });
    }

    // 1. Total Products
    const { count: productCount, error: productError } = await supabase
      .from("products")
      .select("*", { count: "exact", head: true })
      .eq("store_id", store.id)
      .eq("is_deleted", false);

    // 2. Low Stock Products
    const { data: lowStockProducts } = await supabase
      .from("products")
      .select("id, name, stock_qty, price")
      .eq("store_id", store.id)
      .eq("is_deleted", false)
      .lt("stock_qty", 10)
      .order("stock_qty", { ascending: true })
      .limit(5);

    // 3. Sales & Active Orders
    // We get order_items for this seller, joined with their parent order
    const { data: orderItems } = await supabase
      .from("order_items")
      .select(`
        id,
        order_id,
        total_price,
        created_at,
        orders!inner(status)
      `)
      .eq("order_seller_id", store.id);

    let totalSales = 0;
    let activeOrders = new Set();
    const salesByDate: Record<string, number> = {};

    if (orderItems) {
      orderItems.forEach((item: any) => {
        // Calculate Total Sales (excluding cancelled)
        if (item.orders.status !== "cancelled") {
          totalSales += Number(item.total_price);

          // Construct 7-day chart data
          const date = new Date(item.created_at).toISOString().split('T')[0];
          salesByDate[date] = (salesByDate[date] || 0) + Number(item.total_price);
        }

        // Calculate Active Orders count
        if (!["delivered", "cancelled", "returned"].includes(item.orders.status)) {
          activeOrders.add(item.order_id);
        }
      });
    }

    // Format chart date for last 7 days
    const chartData = [];
    for (let i = 6; i >= 0; i--) {
      const d = new Date();
      d.setDate(d.getDate() - i);
      const dateString = d.toISOString().split('T')[0];
      const displayDate = d.toLocaleDateString('en-US', { weekday: 'short' });
      chartData.push({
        date: displayDate,
        sales: salesByDate[dateString] || 0
      });
    }

    // 4. Recent Orders
    const { data: recentOrderItems } = await supabase
      .from("order_items")
      .select(`
        id,
        order_id,
        product_name,
        total_price,
        created_at,
        orders!inner(order_number, status, total)
      `)
      .eq("order_seller_id", store.id)
      .order("created_at", { ascending: false })
      .limit(5);

    // Deduplicate recent orders (since one order might have multiple items)
    const recentOrdersMap = new Map();
    if (recentOrderItems) {
      recentOrderItems.forEach((item: any) => {
        if (!recentOrdersMap.has(item.order_id)) {
          recentOrdersMap.set(item.order_id, {
            id: item.order_id,
            order_number: item.orders.order_number,
            status: item.orders.status,
            date: item.created_at,
            items: [item.product_name],
            total: item.total_price // we sum it up below
          });
        } else {
          const existing = recentOrdersMap.get(item.order_id);
          existing.items.push(item.product_name);
          existing.total += item.total_price;
        }
      });
    }

    const recentOrders = Array.from(recentOrdersMap.values()).slice(0, 5);

    return NextResponse.json({
      metrics: {
        totalSales,
        activeOrders: activeOrders.size,
        totalProducts: productCount || 0,
        averageRating: store.rating || 0,
      },
      chartData,
      lowStockProducts: lowStockProducts || [],
      recentOrders
    });

  } catch (error: any) {
    console.error("Dashboard API Error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";

export async function POST(request: Request) {
  try {
    const supabase = await createClient();

    // Verify auth
    const { data: { user }, error: userError } = await supabase.auth.getUser();
    if (userError || !user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    // Get seller's store id
    const { data: store } = await supabase
      .from("stores")
      .select("id")
      .eq("user_id", user.id)
      .single();

    if (!store) {
      return NextResponse.json({ error: "Please complete store profile first." }, { status: 400 });
    }

    const { documents } = await request.json();
    if (!documents || !Array.isArray(documents)) {
      return NextResponse.json({ error: "Invalid document data" }, { status: 400 });
    }

    // Insert documents
    // First, maybe delete old ones if re-submitting
    await supabase.from("seller_documents").delete().eq("store_id", store.id);

    const docsToInsert = documents.map(doc => ({
      store_id: store.id,
      document_type: doc.document_type,
      document_url: doc.document_url,
      is_verified: false,
    }));

    const { error: insertError } = await supabase
      .from("seller_documents")
      .insert(docsToInsert);

    if (insertError) {
      console.error("Document insert error:", insertError);
      return NextResponse.json({ error: insertError.message }, { status: 500 });
    }

    return NextResponse.json({ success: true });
  } catch (err: any) {
    console.error("Documents API Error:", err);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";

export async function GET(request: Request, { params }: { params: Promise<{ id: string }> }) {
  try {
    const supabase = await createClient();
    const { id: orderId } = await params;

    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

    const { data: store } = await supabase.from("stores").select("id").eq("user_id", user.id).single();
    if (!store) return NextResponse.json({ error: "Store not found" }, { status: 404 });

    // Fetch the main order
    const { data: order, error: orderError } = await supabase
      .from("orders")
      .select("*")
      .eq("id", orderId)
      .single();

    if (orderError || !order) return NextResponse.json({ error: "Order not found" }, { status: 404 });

    // Fetch items belonging specifically to this seller
    const { data: items, error: itemsError } = await supabase
      .from("order_items")
      .select("*")
      .eq("order_id", orderId)
      .eq("order_seller_id", store.id);

    if (itemsError || !items || items.length === 0) {
      return NextResponse.json({ error: "No items found for your store in this order." }, { status: 403 });
    }

    return NextResponse.json({ order, items });

  } catch (error: any) {
    console.error("Order GET Error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

export async function PUT(request: Request, { params }: { params: Promise<{ id: string }> }) {
  try {
    const supabase = await createClient();
    const { id: orderId } = await params;

    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

    const { data: store } = await supabase.from("stores").select("id").eq("user_id", user.id).single();
    if (!store) return NextResponse.json({ error: "Store not found" }, { status: 404 });

    // Verify they actually own items in this order
    const { data: items } = await supabase
      .from("order_items")
      .select("id")
      .eq("order_id", orderId)
      .eq("order_seller_id", store.id)
      .limit(1);

    if (!items || items.length === 0) {
      return NextResponse.json({ error: "Forbidden" }, { status: 403 });
    }

    let payload;
    try {
      payload = await request.json();
    } catch {
      payload = {};
    }

    if (!payload.status) {
      return NextResponse.json({ error: "Missing status" }, { status: 400 });
    }

    // Update the main order status
    // Note: In a multi-vendor cart, updating orders.status updates it for ALL sellers.
    // Given the current simple schema, applying it to orders is the correct path.
    const { error: updateError } = await supabase
      .from("orders")
      .update({
        status: payload.status,
        updated_at: new Date().toISOString()
      })
      .eq("id", orderId);

    if (updateError) {
      return NextResponse.json({ error: updateError.message }, { status: 500 });
    }

    return NextResponse.json({ success: true, status: payload.status });

  } catch (error: any) {
    console.error("Order PUT Error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";

export async function GET(request: Request) {
  try {
    const supabase = await createClient();

    const { data: { user } } = await supabase.auth.getUser();
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const { data: store } = await supabase
      .from("stores")
      .select("id")
      .eq("user_id", user.id)
      .single();

    if (!store) {
      return NextResponse.json({ error: "Store not found" }, { status: 404 });
    }

    // Parse filters
    const { searchParams } = new URL(request.url);
    const status = searchParams.get("status");

    // Fetch order items belonging to the seller
    let query = supabase
      .from("order_items")
      .select(`
        id,
        order_id,
        product_name,
        quantity,
        total_price,
        created_at,
        orders!inner(order_number, status, total, delivery_date, created_at)
      `)
      .eq("order_seller_id", store.id)
      .order("created_at", { ascending: false });

    if (status && status !== "all") {
      // Must filter orders!inner by status
      query = query.eq("orders.status", status);
    }

    const { data: orderItems, error } = await query;

    if (error) {
      console.error("Orders DB Error:", error);
      return NextResponse.json({ error: "Database error" }, { status: 500 });
    }

    // Group items by order to present one row per Order
    const ordersMap = new Map();
    orderItems?.forEach((item: any) => {
      if (!ordersMap.has(item.order_id)) {
        ordersMap.set(item.order_id, {
          id: item.order_id,
          order_number: item.orders.order_number,
          status: item.orders.status,
          date: item.orders.created_at,
          delivery_date: item.orders.delivery_date,
          items: 1,
          total: Number(item.total_price)
        });
      } else {
        const existing = ordersMap.get(item.order_id);
        existing.items += 1;
        existing.total += Number(item.total_price);
      }
    });

    const formattedOrders = Array.from(ordersMap.values()).sort((a: any, b: any) => 
      new Date(b.date).getTime() - new Date(a.date).getTime()
    );

    return NextResponse.json(formattedOrders);

  } catch (error: any) {
    console.error("Orders API Error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
