export async function POST(request: Request) {
  try {
    const supabase = await createClient();

    // Verify auth
    const { data: { user }, error: userError } = await supabase.auth.getUser();
    if (userError || !user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    // Verify role
    const { data: userData } = await supabase
      .from("users")
      .select("role")
      .eq("id", user.id)
      .single();

    if (userData?.role !== "seller" && userData?.role !== "admin") {
      return NextResponse.json({ error: "Forbidden: Not a seller" }, { status: 403 });
    }

    const payload = await request.json();
    const {
      store_name,
      description,
      phone,
      email,
      address,
      pin_code,
      gst_number,
      logo_url,
      banner_url,
    } = payload;

    if (!store_name || !address || !phone) {
      return NextResponse.json({ error: "Missing required fields" }, { status: 400 });
    }

    // Generate slug from store name
    const slug = store_name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');

    // Ensure slug uniqueness (simple implementation, append random numbers if exists)
    // For a robust system, we would check the DB first.
    const finalSlug = slug + "-" + Math.floor(1000 + Math.random() * 9000);

    // Upsert store (a user should only have 1 store)
    // To do an upsert safely, let's see if one exists first.
    const { data: existingStore } = await supabase
      .from("stores")
      .select("id")
      .eq("user_id", user.id)
      .single();

    if (existingStore) {
      // Update existing
      const { error: updateError } = await supabase
        .from("stores")
        .update({
          store_name,
          description,
          phone,
          email,
          address,
          pin_code,
          gst_number,
          logo_url,
          banner_url,
          updated_at: new Date().toISOString(),
        })
        .eq("id", existingStore.id);

      if (updateError) {
         console.error("Store update error:", updateError);
         return NextResponse.json({ error: updateError.message }, { status: 500 });
      }
      return NextResponse.json({ success: true, storeId: existingStore.id });
    } else {
      // Insert new
      const { data: newStore, error: insertError } = await supabase
        .from("stores")
        .insert({
          user_id: user.id,
          store_name,
          slug: finalSlug,
          description,
          phone,
          email,
          address,
          pin_code,
          gst_number,
          logo_url,
          banner_url,
          status: "pending",
          is_active: false,
          rating: 0,
          total_orders: 0,
          total_products: 0,
        })
        .select("id")
        .single();

      if (insertError) {
         console.error("Store insert error:", insertError);
         return NextResponse.json({ error: insertError.message }, { status: 500 });
      }

      return NextResponse.json({ success: true, storeId: newStore.id });
    }
  } catch (err: any) {
    console.error("Store API Error:", err);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

