                      <div className="flex h-full items-center justify-center">
                        <Package className="h-6 w-6 text-gray-400" />
                      </div>
                    )}
                  </div>
                  <div className="flex-1 min-w-0">
                    <h4 className="font-bold text-gray-900 truncate">{item.product_name}</h4>
                    {item.variant_name && (
                      <p className="text-xs text-gray-500 mt-0.5">Variant: {item.variant_name}</p>
                    )}
                    <div className="mt-2 flex items-center gap-4 text-sm">
                      <span className="font-medium bg-gray-100 px-2 py-0.5 rounded text-gray-700">Qty: {item.quantity}</span>
                      <span className="text-gray-500">@ {formatCurrency(item.unit_price)} each</span>
                    </div>
                  </div>
                  <div className="text-right shrink-0">
                    <p className="font-bold text-gray-900">{formatCurrency(item.total_price)}</p>
                  </div>
                </div>
              ))}
            </div>
            <div className="px-6 py-4 bg-gray-50 border-t border-gray-100 flex justify-between items-center">
              <span className="text-sm font-medium text-gray-600">Your Fulfillable Total</span>
              <span className="text-lg font-bold text-gray-900">
                {formatCurrency(items.reduce((sum: number, item: any) => sum + Number(item.total_price), 0))}
              </span>
            </div>
          </div>

          {/* Action Panel */}
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
            <h3 className="font-semibold text-gray-900 mb-4 flex items-center gap-2">
              <AlertCircle className="h-4 w-4 text-emerald-600" />
              Update Order Status
            </h3>

            <div className="flex flex-wrap gap-3">
              {order.status === "pending" && (
                <Button 
                  onClick={() => updateStatus("processing")} 
                  disabled={isUpdating}
                  className="bg-blue-600 hover:bg-blue-700 text-white shadow-sm"
                >
                  <Clock className="w-4 h-4 mr-2" />
                  Mark as Processing
                </Button>
              )}
              {order.status === "processing" && (
                <Button 
                  onClick={() => updateStatus("shipped")} 
                  disabled={isUpdating}
                  className="bg-indigo-600 hover:bg-indigo-700 text-white shadow-sm"
                >
                  <Truck className="w-4 h-4 mr-2" />
                  Mark as Shipped
                </Button>
              )}
              {order.status === "shipped" && (
                <span className="text-sm text-gray-500 bg-gray-50 px-4 py-2 rounded-lg border">
                  Waiting for Rider to mark 'Out for Delivery'.
                </span>
              )}
              {!["pending", "processing"].includes(order.status) && order.status !== "shipped" && (
                <span className="text-sm text-gray-500 bg-gray-50 px-4 py-2 rounded-lg border">
                  Status cannot be updated by seller at this stage.
                </span>
              )}
            </div>
          </div>
        </div>

        {/* Right Column: Customer Info */}
        <div className="space-y-6">
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
            <h3 className="font-semibold text-gray-900 mb-4 flex items-center gap-2">
              <User className="h-4 w-4 text-emerald-600" />
              Customer Details
            </h3>
            <div className="space-y-3 text-sm">
              <div>
                <p className="text-gray-500 text-xs uppercase tracking-wider mb-0.5">Name</p>
                <p className="font-medium text-gray-900">{deliveryAddress.fullName || "N/A"}</p>
              </div>
              <div>
                <p className="text-gray-500 text-xs uppercase tracking-wider mb-0.5">Contact</p>
                <p className="font-medium text-gray-900">{deliveryAddress.phone || "N/A"}</p>
              </div>
            </div>
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
            <h3 className="font-semibold text-gray-900 mb-4 flex items-center gap-2">
              <MapPin className="h-4 w-4 text-emerald-600" />
              Delivery Address
            </h3>
            <div className="text-sm text-gray-700 leading-relaxed bg-gray-50 p-4 rounded-xl border border-gray-100">
              <p className="font-medium text-gray-900">{deliveryAddress.fullName}</p>
              <p className="mt-1">{deliveryAddress.addressLine1}</p>
              {deliveryAddress.addressLine2 && <p>{deliveryAddress.addressLine2}</p>}
              <p className="mt-1">{deliveryAddress.city}, {deliveryAddress.state} {deliveryAddress.pinCode}</p>
              {deliveryAddress.landmark && <p className="mt-2 text-xs text-gray-500">Landmark: {deliveryAddress.landmark}</p>}
            </div>
          </div>

        </div>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { ArrowRight, Loader2, ChevronDown } from "lucide-react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Separator } from "@/components/ui/separator";
import { createClient } from "@/lib/supabase/client";
import { registerSchema, otpSchema } from "@/lib/validations";
import type { RegisterFormData, OtpFormData } from "@/lib/validations";
import { APP_NAME, ROLE_DASHBOARDS, type UserRole } from "@/lib/constants";

// ---------------------------------------------------------------------------
// Variant configuration — i18n-ready string map
// ---------------------------------------------------------------------------
type RegisterVariant = "buyer" | "seller";

interface VariantConfig {
  heading: string;
  subtitle: string;
  loginHref: string;
  loginLabel: string;
  defaultRedirect: string;
  oauthLabel: string;
  apiRole: string;
}

const VARIANT_CONFIG: Record<RegisterVariant, VariantConfig> = {
  buyer: {
    heading: "Create your Account",
    subtitle: `Enter your details to start shopping on ${APP_NAME}.`,
    loginHref: "/login",
    loginLabel: "Login",
    defaultRedirect: "/",
    oauthLabel: "OR CONTINUE WITH",
    apiRole: "buyer",
  },
  seller: {
    heading: "Register your Store",
    subtitle: "Create a seller account to start listing products.",
    loginHref: "/seller/login",
    loginLabel: "Login",
    defaultRedirect: "/seller/store",
    oauthLabel: "OR CONTINUE WITH",
    apiRole: "seller",
  },
};

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------
interface RegisterFormProps {
  variant: RegisterVariant;
}

export function RegisterForm({ variant }: RegisterFormProps) {
  const config = VARIANT_CONFIG[variant];
  const router = useRouter();

  const [step, setStep] = useState<"info" | "otp">("info");
  const [formData, setFormData] = useState<RegisterFormData | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const infoForm = useForm<RegisterFormData>({
    resolver: zodResolver(registerSchema),
    defaultValues: { full_name: "", phone: "", email: "" },
  });

  const otpForm = useForm<OtpFormData>({
    resolver: zodResolver(otpSchema),
    defaultValues: { otp: "" },
  });

  // Step 1: Send OTP
  const handleSendOtp = async (data: RegisterFormData) => {
    setIsLoading(true);
    try {
      const supabase = createClient();
      const { error } = await supabase.auth.signInWithOtp({
        phone: `+91${data.phone}`,
      });

      if (error) {
        toast.error(error.message || "Failed to send OTP");
        return;
      }

      setFormData(data);
      setStep("otp");
      toast.success("OTP sent to your phone!");
    } catch {
      toast.error("Something went wrong. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  // Step 2: Verify OTP + create user profile
  const handleVerifyOtp = async (data: OtpFormData) => {
    if (!formData) return;
    setIsLoading(true);
    try {
      const supabase = createClient();
      const { data: authData, error } = await supabase.auth.verifyOtp({
        phone: `+91${formData.phone}`,
        token: data.otp,
        type: "sms",
      });

      if (error) {
        toast.error(error.message || "Invalid OTP. Please try again.");
        return;
      }

      if (authData.user) {
        const response = await fetch("/api/auth/register", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            id: authData.user.id,
            full_name: formData.full_name,
            phone: formData.phone,
            email: formData.email || null,
            role: config.apiRole,
          }),
        });

        const result = await response.json();

        if (!response.ok) {
          toast.error(result.error || "Failed to create account");
          return;
        }

        toast.success("Account created successfully! 🎉");
        router.push(config.defaultRedirect);
        router.refresh();
      }
    } catch {
      toast.error("Registration failed. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="w-full bg-surface-lowest">
      {/* Auth Navigation Tabs */}
      <div className="flex items-center gap-8 mb-8 border-b border-surface-container-high relative">
        <div className="relative pb-3">
          <Link
            href={config.loginHref}
            className="text-on-surface-variant hover:text-on-surface transition-colors"
          >
            {config.loginLabel}
          </Link>
        </div>
        <div className="relative pb-3">
          <span className="text-primary font-bold">Register</span>
          <div className="absolute -bottom-px left-0 w-full h-[2px] bg-primary" />
        </div>
      </div>

      {step === "info" ? (
        <div className="space-y-6">
          <div className="space-y-2 mb-8">
            <h1 className="text-[28px] font-bold font-serif text-on-surface tracking-tight">
              {config.heading}
            </h1>
            <p className="text-on-surface-variant text-sm">
              {config.subtitle}
            </p>
          </div>

          <form
            onSubmit={infoForm.handleSubmit(handleSendOtp)}
            className="space-y-6"
          >
            <div className="space-y-2">
              <Label
                htmlFor="register-fullname"
                className="text-xs font-semibold text-on-surface-variant uppercase tracking-wider"
              >
                FULL NAME
              </Label>
              <Input
                id="register-fullname"
                placeholder="Your full name"
                className="w-full h-12 bg-surface-container border-0 shadow-none focus-visible:ring-1 focus-visible:ring-primary rounded-lg px-4 text-base placeholder:text-on-surface-variant/50"
                {...infoForm.register("full_name")}
              />
              {infoForm.formState.errors.full_name && (
                <p className="text-xs text-error mt-1 ml-1">
                  {infoForm.formState.errors.full_name.message}
                </p>
              )}
            </div>

            <div className="space-y-2">
              <Label
                htmlFor="register-phone"
                className="text-xs font-semibold text-on-surface-variant uppercase tracking-wider"
              >
                PHONE NUMBER
              </Label>
              <div className="flex items-center gap-2">
                <div className="flex items-center justify-between w-20 h-12 bg-surface-container rounded-lg px-3 cursor-pointer">
                  <span className="text-sm font-medium text-on-surface">
                    +91
                  </span>
                  <ChevronDown className="h-4 w-4 text-on-surface-variant" />
                </div>
                <Input
                  id="register-phone"
                  type="tel"
                  placeholder="000 000 0000"
                  className="flex-1 h-12 bg-surface-container border-0 shadow-none focus-visible:ring-1 focus-visible:ring-primary rounded-lg px-4 text-base placeholder:text-on-surface-variant/50"
                  maxLength={10}
                  {...infoForm.register("phone")}
                />
              </div>
              {infoForm.formState.errors.phone && (
                <p className="text-xs text-error mt-1 ml-1">
                  {infoForm.formState.errors.phone.message}
                </p>
              )}
            </div>

            <div className="space-y-2">
              <Label
                htmlFor="register-email"
                className="text-xs font-semibold text-on-surface-variant uppercase tracking-wider"
              >
                EMAIL{" "}
                <span className="text-on-surface-variant/50 font-normal">
                  (OPTIONAL)
                </span>
              </Label>
              <Input
                id="register-email"
                type="email"
                placeholder="your@email.com"
                className="w-full h-12 bg-surface-container border-0 shadow-none focus-visible:ring-1 focus-visible:ring-primary rounded-lg px-4 text-base placeholder:text-on-surface-variant/50"
                {...infoForm.register("email")}
              />
              {infoForm.formState.errors.email && (
                <p className="text-xs text-error mt-1 ml-1">
                  {infoForm.formState.errors.email.message}
                </p>
              )}
            </div>

            <Button
              type="submit"
              className="w-full h-12 bg-primary hover:bg-primary/90 text-white rounded-full shadow-none transition-colors font-medium text-base mt-2"
              disabled={isLoading}
            >
              {isLoading ? (
                <Loader2 className="h-5 w-5 animate-spin mr-2" />
              ) : null}
              Send OTP
              {!isLoading && <ArrowRight className="h-4 w-4 ml-2" />}
            </Button>

            <div className="relative py-4">
              <Separator className="bg-surface-container-high" />
              <span className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 bg-surface-lowest px-4 text-[11px] font-bold text-on-surface-variant uppercase tracking-widest">
                {config.oauthLabel}
              </span>
            </div>

            <Button
              type="button"
              variant="outline"
              className="w-full h-12 rounded-full border-surface-container text-on-surface hover:bg-surface-container transition-colors font-medium"
              disabled
            >
              <svg className="h-4 w-4 mr-3" viewBox="0 0 24 24">
                <path
                  d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92a5.06 5.06 0 01-2.2 3.32v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.1z"
                  fill="#4285F4"
                />
                <path
                  d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
                  fill="#34A853"
                />
                <path
                  d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
                  fill="#FBBC05"
                />
                <path
                  d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
                  fill="#EA4335"
                />
              </svg>
              Continue with Google
            </Button>
          </form>
        </div>
      ) : (
        <div className="space-y-6">
          <div className="space-y-2 mb-8">
            <h1 className="text-[28px] font-bold font-serif text-on-surface tracking-tight">
              Verify your Identity
            </h1>
            <p className="text-on-surface-variant text-sm flex items-center gap-2">
              Code sent to{" "}
              <strong className="text-on-surface">
                +91 {formData?.phone}
              </strong>
              <button
                type="button"
                onClick={() => setStep("info")}
                className="text-primary hover:underline text-xs"
              >
                Change
              </button>
            </p>
          </div>

          <form
            onSubmit={otpForm.handleSubmit(handleVerifyOtp)}
            className="space-y-6"
          >
            <div className="space-y-2">
              <Label
                htmlFor="register-otp"
                className="text-xs font-semibold text-on-surface-variant uppercase tracking-wider"
              >
                ENTER 6-DIGIT OTP
              </Label>
              <Input
                id="register-otp"
                type="text"
                placeholder="000000"
                className="w-full h-14 bg-surface-container border-0 shadow-none focus-visible:ring-1 focus-visible:ring-primary rounded-lg text-center text-2xl tracking-[0.5em] font-mono"
                maxLength={6}
                autoFocus
                {...otpForm.register("otp")}
              />
              {otpForm.formState.errors.otp && (
                <p className="text-xs text-error mt-1 ml-1">
                  {otpForm.formState.errors.otp.message}
                </p>
              )}
            </div>

            <Button
              type="submit"
              className="w-full h-12 bg-primary hover:bg-primary/90 text-white rounded-full shadow-none transition-colors font-medium text-base"
              disabled={isLoading}
            >
              {isLoading && <Loader2 className="h-5 w-5 animate-spin mr-2" />}
              Verify & Enter
            </Button>

            <button
              type="button"
              onClick={() => formData && handleSendOtp(formData)}
              className="w-full text-sm font-medium text-on-surface-variant hover:text-on-surface transition-colors py-2"
              disabled={isLoading}
            >
              Didn&apos;t receive code?{" "}
              <span className="text-primary">Resend</span>
            </button>
          </form>
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState, useCallback } from "react";
import { useRouter } from "next/navigation";
import { useForm, useFieldArray } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { toast } from "sonner";
import { Loader2, Plus, Trash2, Save } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Switch } from "@/components/ui/switch";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";
import { ImageUpload } from "@/components/shared/image-upload";
import { PRODUCT_UNITS, OCCASIONS, STORAGE_BUCKETS } from "@/lib/constants";
import type { Category } from "@/types";

// ---------- Schema ----------
const variantSchema = z.object({
  variant_name: z.string().min(1, "Required"),
  price: z.number().min(0, "Price must be positive"),
  sale_price: z.number().min(0).optional(),
  stock_qty: z.number().min(0),
  sku: z.string().optional(),
});

const productFormSchema = z.object({
  name: z.string().min(2, "Name must be at least 2 characters"),
  description: z.string().optional(),
  price: z.number().min(1, "Price is required"),
  sale_price: z.number().min(0).optional(),
  sku: z.string().optional(),
  stock_qty: z.number().min(0),
  unit: z.string(),
  category_id: z.string().min(1, "Category is required"),
  occasion: z.string().optional(),
  care_instructions: z.string().optional(),
  tags: z.string().optional(), // comma separated
  is_featured: z.boolean(),
  is_active: z.boolean(),
  variants: z.array(variantSchema).optional(),
});

type ProductFormData = z.infer<typeof productFormSchema>;

interface ProductFormProps {
  initialData?: ProductFormData & { id?: string; images?: string[] };
  mode: "create" | "edit";
}

export function ProductForm({ initialData, mode }: ProductFormProps) {
  const router = useRouter();
  const [isSaving, setIsSaving] = useState(false);
  const [categories, setCategories] = useState<Category[]>([]);
  const [imageUrls, setImageUrls] = useState<string[]>(
    initialData?.images || []
  );

  const form = useForm<ProductFormData>({
    resolver: zodResolver(productFormSchema),
    defaultValues: initialData || {
      name: "",
      description: "",
      price: 0,
      sale_price: undefined,
      sku: "",
      stock_qty: 0,
      unit: "piece",
      category_id: "",
      occasion: "",
      care_instructions: "",
      tags: "",
      is_featured: false,
      is_active: true,
      variants: [],
    },
  });

  const { fields, append, remove } = useFieldArray({
    control: form.control,
    name: "variants",
  });

  // Fetch categories
  useEffect(() => {
    const fetchCategories = async () => {
      try {
        const res = await fetch("/api/categories");
        const json = await res.json();
        if (res.ok && json.data) {
          // Flatten tree for select
          const flat: Category[] = [];
          for (const parent of json.data) {
            flat.push(parent);
            if (parent.children) {
              for (const child of parent.children) {
                flat.push(child);
              }
            }
          }
          setCategories(flat);
        }
      } catch {
        // silent
      }
    };
    fetchCategories();
  }, []);

  const handleSubmit = useCallback(
    async (data: ProductFormData) => {
      if (imageUrls.length === 0) {
        toast.error("Please upload at least one image");
        return;
      }

      setIsSaving(true);
      try {
        const payload = {
          ...data,
          tags: data.tags
            ? data.tags.split(",").map((t) => t.trim()).filter(Boolean)
            : [],
          images: imageUrls,
        };

        const url =
          mode === "edit" && initialData?.id
            ? `/api/products/${initialData.id}`
            : "/api/products";
        const method = mode === "edit" ? "PUT" : "POST";

        const res = await fetch(url, {
          method,
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(payload),
        });

        const json = await res.json();

        if (!res.ok) {
          toast.error(json.error || "Operation failed");
          return;
        }

        toast.success(
          mode === "edit" ? "Product updated!" : "Product created! 🎉"
        );
        router.push("/seller/products");
        router.refresh();
      } catch {
        toast.error("Something went wrong");
      } finally {
        setIsSaving(false);
      }
    },
    [imageUrls, mode, initialData, router]
  );

  return (
    <form onSubmit={form.handleSubmit(handleSubmit)} className="space-y-8 max-w-4xl mx-auto pb-24">
      {/* Section 1: Basic Info */}
      <Card className="bg-surface-lowest border-0 shadow-ambient rounded-3xl overflow-hidden">
        <CardHeader className="bg-surface-container-lowest/50 px-8 pt-8 pb-6 border-b border-outline-variant/20">
          <CardTitle className="text-xl font-serif text-on-surface">Basic Information</CardTitle>
          <CardDescription className="text-on-surface-variant">Product name, category, and description</CardDescription>
        </CardHeader>
        <CardContent className="space-y-6 px-8 py-6">
          <div className="space-y-2">
            <Label htmlFor="name" className="text-on-surface font-semibold">Product Name *</Label>
            <Input 
              id="name" 
              placeholder="e.g. Rare Monstera Albo" 
              className="h-12 bg-surface-container-low border-0 focus-visible:ring-1 focus-visible:ring-primary rounded-xl px-4 text-base shadow-none"
              {...form.register("name")} 
            />
            {form.formState.errors.name && (
              <p className="text-xs text-error mt-1">{form.formState.errors.name.message}</p>
            )}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <Label className="text-on-surface font-semibold">Category *</Label>
              <Select
                value={form.watch("category_id") || ""}
                onValueChange={(val) => form.setValue("category_id", val ?? "")}
              >
                <SelectTrigger className="h-12 bg-surface-container-low border-0 shadow-none rounded-xl px-4 font-medium">
                  <SelectValue placeholder="Select category" />
                </SelectTrigger>
                <SelectContent className="rounded-xl shadow-ambient border-0 bg-surface-lowest">
                  {categories.map((c) => (
                    <SelectItem key={c.id} value={c.id} className="rounded-lg">
                      {c.parent_id ? `↳ ${c.name}` : c.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
