"use client";

import { useCallback, useState } from "react";
import Image from "next/image";
import { Upload, X, Loader2, ImageIcon } from "lucide-react";
import { cn } from "@/lib/utils";
import { toast } from "sonner";
import { MAX_IMAGE_SIZE_MB, ACCEPTED_IMAGE_TYPES } from "@/lib/constants";

interface ImageUploadProps {
  value: string[];
  onChange: (urls: string[]) => void;
  maxImages?: number;
  bucket: string;
  folder?: string;
  className?: string;
}

export function ImageUpload({
  value = [],
  onChange,
  maxImages = 8,
  bucket,
  folder = "",
  className,
}: ImageUploadProps) {
  const [uploading, setUploading] = useState(false);

  const handleUpload = useCallback(
    async (files: FileList | null) => {
      if (!files || files.length === 0) return;

      const remaining = maxImages - value.length;
      if (remaining <= 0) {
        toast.error(`Maximum ${maxImages} images allowed`);
        return;
      }

      const filesToUpload = Array.from(files).slice(0, remaining);

      // Validate files
      for (const file of filesToUpload) {
        if (!ACCEPTED_IMAGE_TYPES.includes(file.type)) {
          toast.error(`${file.name}: Invalid format. Use JPEG, PNG, or WebP`);
          return;
        }
        if (file.size > MAX_IMAGE_SIZE_MB * 1024 * 1024) {
          toast.error(`${file.name}: File too large. Max ${MAX_IMAGE_SIZE_MB}MB`);
          return;
        }
      }

      setUploading(true);
      const uploadedUrls: string[] = [];

      try {
        for (const file of filesToUpload) {
          const formData = new FormData();
          formData.append("file", file);
          formData.append("bucket", bucket);
          if (folder) formData.append("folder", folder);

          const response = await fetch("/api/upload", {
            method: "POST",
            body: formData,
          });

          const result = await response.json();

          if (!response.ok) {
            toast.error(result.error || `Failed to upload ${file.name}`);
            continue;
          }

          uploadedUrls.push(result.url);
        }

        if (uploadedUrls.length > 0) {
          onChange([...value, ...uploadedUrls]);
          toast.success(
            `${uploadedUrls.length} image${uploadedUrls.length > 1 ? "s" : ""} uploaded`
          );
        }
      } catch {
        toast.error("Upload failed. Please try again.");
      } finally {
        setUploading(false);
      }
    },
    [value, onChange, maxImages, bucket, folder]
  );

  const handleRemove = (index: number) => {
    const updated = [...value];
    updated.splice(index, 1);
    onChange(updated);
  };

  return (
    <div className={cn("space-y-3", className)}>
      {/* Preview Grid */}
      {value.length > 0 && (
        <div className="grid grid-cols-4 gap-3">
          {value.map((url, index) => (
            <div
              key={url}
              className="relative aspect-square rounded-lg border overflow-hidden group bg-gray-50"
            >
              <Image
                src={url}
                alt={`Upload ${index + 1}`}
                fill
                className="object-cover"
                sizes="120px"
              />
              <button
                type="button"
                onClick={() => handleRemove(index)}
                className="absolute top-1 right-1 h-6 w-6 rounded-full bg-red-500 text-white flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity shadow-sm"
              >
                <X className="h-3.5 w-3.5" />
              </button>
              {index === 0 && (
                <span className="absolute bottom-1 left-1 text-[9px] bg-emerald-600 text-white px-1.5 py-0.5 rounded font-medium">
                  Primary
                </span>
              )}
            </div>
          ))}
        </div>
      )}

      {/* Upload Zone */}
      {value.length < maxImages && (
        <label
          className={cn(
            "flex flex-col items-center justify-center rounded-lg border-2 border-dashed cursor-pointer transition-colors py-8",
            uploading
              ? "border-emerald-300 bg-emerald-50"
              : "border-gray-300 hover:border-emerald-400 hover:bg-emerald-50/50"
          )}
        >
          <input
            type="file"
            accept={ACCEPTED_IMAGE_TYPES.join(",")}
            multiple
            className="hidden"
            onChange={(e) => handleUpload(e.target.files)}
            disabled={uploading}
          />
          {uploading ? (
            <>
              <Loader2 className="h-8 w-8 text-emerald-500 animate-spin mb-2" />
              <p className="text-sm text-emerald-600 font-medium">
                Uploading...
              </p>
            </>
          ) : (
            <>
              <div className="flex h-12 w-12 items-center justify-center rounded-full bg-gray-100 mb-2">
                <Upload className="h-5 w-5 text-gray-500" />
              </div>
              <p className="text-sm font-medium text-gray-700">
                Click to upload images
              </p>
              <p className="text-xs text-muted-foreground mt-1">
                JPEG, PNG, WebP • Max {MAX_IMAGE_SIZE_MB}MB •{" "}
                {value.length}/{maxImages} uploaded
              </p>
            </>
          )}
        </label>
      )}
    </div>
  );
}

"use client";

import React, { useState, useEffect } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { Home, Search, ShoppingCart, Heart, User } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { useCartStore } from "@/stores/cart-store";

const navItems = [
  { name: "Home", href: "/", icon: Home },
  { name: "Shop", href: "/shop", icon: Search },
  { name: "Cart", href: "/cart", icon: ShoppingCart, showBadge: true },
  { name: "Wishlist", href: "/account/wishlist", icon: Heart },
  { name: "Account", href: "/account/profile", icon: User },
];

export default function MobileNav() {
  const pathname = usePathname();
  const totalItems = useCartStore((s) => s.totalItems);

  const [isMounted, setIsMounted] = React.useState(false);
  React.useEffect(() => {
    setIsMounted(true);
  }, []);

  return (
    <nav className="fixed bottom-0 left-0 right-0 z-50 md:hidden bg-white border-t shadow-[0_-2px_10px_rgba(0,0,0,0.05)]">
      <div className="flex items-center justify-around h-16">
        {navItems.map((item) => {
          const Icon = item.icon;
          const isActive =
            pathname === item.href ||
            (item.href !== "/" && pathname.startsWith(item.href));

          return (
            <Link
              key={item.name}
              href={item.href}
              className={`flex flex-col items-center gap-0.5 px-3 py-1.5 transition-colors ${
                isActive
                  ? "text-emerald-600"
                  : "text-gray-500 hover:text-gray-700"
              }`}
            >
              <div className="relative">
                <Icon className="h-5 w-5" />
                {item.showBadge && isMounted && totalItems() > 0 && (
                  <Badge className="absolute -top-2 -right-3 h-4 min-w-4 flex items-center justify-center p-0 text-[9px] bg-emerald-600">
                    {totalItems()}
                  </Badge>
                )}
              </div>
              <span className="text-[10px] font-medium">{item.name}</span>
            </Link>
          );
        })}
      </div>
    </nav>
  );
}

"use client";

import { useEffect, useCallback } from "react";
import { createClient } from "@/lib/supabase/client";
import { useAuthStore } from "@/stores/auth-store";
import type { AuthUser } from "@/types";
import type { AuthChangeEvent, Session, User as SupabaseUser } from "@supabase/supabase-js";

/**
 * Hook that manages auth state synchronization between Supabase and Zustand.
 * Should be called once at the app root level (via AuthProvider).
 */
export function useAuth() {
  const { user, isLoading, isAuthenticated, setUser, setLoading, clearUser } =
    useAuthStore();

  const fetchProfile = useCallback(
    async (userId: string, sessionUser?: SupabaseUser) => {
      const supabase = createClient();
      const { data, error } = await supabase
        .from("users")
        .select("id, full_name, phone, email, avatar_url, role, is_active")
        .eq("id", userId)
        .single();

      if (error || !data) {
        // No profile row yet — use session data as fallback
        // This happens when user just registered via OTP but the profile
        // row hasn't been created or RLS blocks the read
        if (sessionUser) {
          const fallbackProfile: AuthUser = {
            id: sessionUser.id,
            full_name: sessionUser.user_metadata?.full_name || sessionUser.phone || "User",
            phone: sessionUser.phone || null,
            email: sessionUser.email || null,
            avatar_url: null,
            role: "buyer",
            is_active: true,
          };
          setUser(fallbackProfile);
          return fallbackProfile;
        }
        clearUser();
        return null;
      }

      const profile = data as AuthUser;
      setUser(profile);
      return profile;
    },
    [setUser, clearUser]
  );

  const signOut = useCallback(async () => {
    const supabase = createClient();
    await supabase.auth.signOut();
    clearUser();
  }, [clearUser]);

  useEffect(() => {
    const supabase = createClient();

    // Check existing session on mount
    const initSession = async () => {
      try {
        const {
          data: { session },
        } = await supabase.auth.getSession();

        if (session?.user) {
          await fetchProfile(session.user.id, session.user);
        } else {
          clearUser();
        }
      } catch (error) {
        console.error("Auth init error:", error);
        clearUser();
      }
    };

    initSession();

    // Listen for auth state changes
    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange(
      async (event: AuthChangeEvent, session: Session | null) => {
        if (event === "SIGNED_IN" && session?.user) {
          await fetchProfile(session.user.id, session.user);
        } else if (event === "SIGNED_OUT") {
          clearUser();
        }
      }
    );

    return () => {
      subscription.unsubscribe();
    };
  }, [fetchProfile, clearUser]);

  return {
    user,
    isLoading,
    isAuthenticated,
    signOut,
    fetchProfile,
  };
}
